        emit_plusminus_inplace_step_inverse_for_test(&mut b, &u, &v, &cu, &cv, &active, &hist, spill, flag, one);
        let ccx = local_count_ccx_for_plusminus_cost(&b.ops[start..]);
        let peak = b.peak_qubits;
        let num_qubits = b.next_qubit as usize;
