    #[test]
    fn plusminus_scaled_public_lane_envelope_with_ambiguous_direction_bits() {
        // Try to avoid storing every ordering bit.  Given k, exactly one output
        // coefficient lane should be divisible by 2^k unless cd=cu-cv is also
        // divisible (or k=0).  Only those ambiguous steps need a persistent
        // direction bit; all other directions are locally recoverable from the
        // ordered coefficient lanes.
        let p = SECP256K1_P;
        let samples = 8192usize;
        let mut rng = 0xa6d1_6635_b17d_5eedu64;
        let mut max_lane_by_step: Vec<[usize; 4]> = Vec::new();
        let mut max_hist_by_step: Vec<usize> = Vec::new();
        let mut max_ambig_by_step: Vec<usize> = Vec::new();
        for _ in 0..samples {
            let mut x = rand_u256(&mut rng);
            if x.is_zero() { x = U256::from(1u64); }
            for (i, (lanes, hist, ambig)) in plusminus_scaled_lane_history_ambig_trace_for_divisor(x, p).into_iter().enumerate() {
                if i == max_lane_by_step.len() {
                    max_lane_by_step.push([0; 4]);
                    max_hist_by_step.push(0);
                    max_ambig_by_step.push(0);
                }
                for j in 0..4 {
                    max_lane_by_step[i][j] = max_lane_by_step[i][j].max(lanes[j]);
                }
                max_hist_by_step[i] = max_hist_by_step[i].max(hist + ambig);
                max_ambig_by_step[i] = max_ambig_by_step[i].max(ambig);
            }
        }
        let mut total_deficit = 0isize;
        let mut worst_step = 0usize;
        for i in 0..max_lane_by_step.len() {
            let slack_sum: isize = max_lane_by_step[i].iter().map(|&w| 256isize - w as isize).sum();
            let d_total = max_hist_by_step[i] as isize - slack_sum;
            if d_total > total_deficit {
                total_deficit = d_total;
                worst_step = i;
            }
        }
        let total_deficit_u = total_deficit.max(0) as usize;
        let scratch = 512 + total_deficit_u;
        let over_google = scratch as isize - 663isize;
        let max_ambig = max_ambig_by_step.iter().copied().max().unwrap_or(0);
        eprintln!(
            "plus-minus lane slack with ambiguous direction bits: steps={}, max_ambig={max_ambig}, total_deficit={total_deficit_u}, scratch={scratch}, over_google={over_google}, worst_step={worst_step}, hist_ambig_at_worst={}",
            max_lane_by_step.len(), max_hist_by_step[worst_step]
        );
        println!("METRIC plusminus_scaled_ambig_dir_steps={}", max_lane_by_step.len());
        println!("METRIC plusminus_scaled_ambig_dir_max_bits={max_ambig}");
        println!("METRIC plusminus_scaled_ambig_dir_total_deficit={total_deficit_u}");
        println!("METRIC plusminus_scaled_ambig_dir_scratch={scratch}");
        println!("METRIC plusminus_scaled_ambig_dir_over_google_bits={over_google}");
        assert!(scratch <= 663, "ambiguous-only direction history misses Google scratch");
    }

    #[test]
    fn plusminus_scaled_public_lane_envelope_with_ambig_dir_and_scale_history_bits() {
        // Best current SOTA shot: the odd-GCD plus-minus route with global
        // scale `2^S`, public slack packing, and Solinas history-carry scale
        // correction. The remaining hard-state question is whether the extra
        // one-bit residual per scale chunk can coexist with unary history and
        // ambiguous-direction bits inside the same public lane-slack envelope.
        // Charge that piece explicitly before doing any circuit integration.
        let p = SECP256K1_P;
        let samples = 32_768usize;
        let seed = 0x5ca1_6635_5ca1_2026u64;

        let mut rng = seed;
        let mut max_scale = 0usize;
        let mut max_steps = 0usize;
        for _ in 0..samples {
            let mut x = rand_u256(&mut rng);
            if x.is_zero() { x = U256::from(1u64); }
            let trace = plusminus_scaled_lane_history_ambig_trace_for_divisor(x, p);
            if let Some((_, hist, _)) = trace.last() {
                max_scale = max_scale.max(*hist);
                max_steps = max_steps.max(trace.len());
            }
        }
        let (_scale_cost_dp, chunk_dp) = solinas_history_carry_scale_dp_for_plusminus(max_scale);

        let mut rng = seed;
        let mut max_lane_by_stage: Vec<[usize; 4]> = Vec::new();
        let mut max_hist_by_stage: Vec<usize> = Vec::new();
        let mut chunk_bits_samples = Vec::with_capacity(samples);
        let mut final_hist_samples = Vec::with_capacity(samples);
        let mut final_scratch_samples = Vec::with_capacity(samples);
        for _ in 0..samples {
            let mut x = rand_u256(&mut rng);
            if x.is_zero() { x = U256::from(1u64); }
            let trace = plusminus_scaled_lane_history_ambig_trace_for_divisor(x, p);
            assert!(!trace.is_empty(), "unexpected empty plus-minus trace");
            for (i, (lanes, hist, ambig)) in trace.iter().copied().enumerate() {
                if i == max_lane_by_stage.len() {
                    max_lane_by_stage.push([0; 4]);
                    max_hist_by_stage.push(0);
                }
                for j in 0..4 {
                    max_lane_by_stage[i][j] = max_lane_by_stage[i][j].max(lanes[j]);
                }
                max_hist_by_stage[i] = max_hist_by_stage[i].max(hist + ambig);
            }
            let (lanes_final, hist_final, ambig_final) = *trace.last().unwrap();
            let chunk_bits = chunk_dp[hist_final];
            let total_hist_final = hist_final + ambig_final + chunk_bits;
            let final_stage = trace.len();
            if final_stage == max_lane_by_stage.len() {
                max_lane_by_stage.push([0; 4]);
                max_hist_by_stage.push(0);
            }
            for j in 0..4 {
                max_lane_by_stage[final_stage][j] = max_lane_by_stage[final_stage][j].max(lanes_final[j]);
            }
            max_hist_by_stage[final_stage] = max_hist_by_stage[final_stage].max(total_hist_final);

            let final_slack_sum: usize = lanes_final.iter().map(|&w| 256usize - w).sum();
            let final_deficit = total_hist_final.saturating_sub(final_slack_sum);
            chunk_bits_samples.push(chunk_bits);
            final_hist_samples.push(total_hist_final);
            final_scratch_samples.push(512 + final_deficit);
        }

        let mut worst_deficit = 0isize;
        let mut worst_stage = 0usize;
        for i in 0..max_lane_by_stage.len() {
            let slack_sum: isize = max_lane_by_stage[i]
                .iter()
                .map(|&w| 256isize - w as isize)
                .sum();
            let deficit = max_hist_by_stage[i] as isize - slack_sum;
            if deficit > worst_deficit {
                worst_deficit = deficit;
                worst_stage = i;
            }
        }
        chunk_bits_samples.sort_unstable();
        final_hist_samples.sort_unstable();
        final_scratch_samples.sort_unstable();
        let p99 = samples * 99 / 100;
        let chunk_bits_p99 = chunk_bits_samples[p99];
        let chunk_bits_max = *chunk_bits_samples.last().unwrap();
        let final_hist_p99 = final_hist_samples[p99];
        let final_hist_max = *final_hist_samples.last().unwrap();
        let final_scratch_p99 = final_scratch_samples[p99];
        let final_scratch_max = *final_scratch_samples.last().unwrap();
        let public_scratch = 512 + worst_deficit.max(0) as usize;
        let over_google = public_scratch as isize - 663isize;
        eprintln!(
            "plus-minus scale-history slack gate: samples={samples}, max_scale={max_scale}, max_steps={max_steps}, chunk_bits_p99={chunk_bits_p99}, chunk_bits_max={chunk_bits_max}, final_hist_p99={final_hist_p99}, final_hist_max={final_hist_max}, final_scratch_p99={final_scratch_p99}, final_scratch_max={final_scratch_max}, public_scratch={public_scratch}, over_google={over_google}, worst_stage={worst_stage}"
        );
        println!("METRIC plusminus_scalehist_samples={samples}");
        println!("METRIC plusminus_scalehist_max_scale={max_scale}");
        println!("METRIC plusminus_scalehist_max_steps={max_steps}");
        println!("METRIC plusminus_scalehist_chunk_bits_p99={chunk_bits_p99}");
        println!("METRIC plusminus_scalehist_chunk_bits_max={chunk_bits_max}");
        println!("METRIC plusminus_scalehist_final_hist_p99={final_hist_p99}");
        println!("METRIC plusminus_scalehist_final_hist_max={final_hist_max}");
        println!("METRIC plusminus_scalehist_final_scratch_p99={final_scratch_p99}");
        println!("METRIC plusminus_scalehist_final_scratch_max={final_scratch_max}");
        println!("METRIC plusminus_scalehist_public_scratch={public_scratch}");
        println!("METRIC plusminus_scalehist_over_google_bits={over_google}");
        println!("METRIC plusminus_scalehist_worst_stage={worst_stage}");
        assert!(public_scratch <= 663, "scale-history bits overflow the public slack envelope");
    }

    #[test]
    fn plusminus_solinas_scale_chunk_workspace_breaks_packed_scratch_gate() {
        // The scale-history ledger above only counts the one-bit residual per
        // Solinas multihalve chunk.  The real k=22 chunk also needs temporary
        // product, high-addend, and Cuccaro carry workspace.  Charge that
        // hardest piece against the packed two-lane state before treating the
        // plus-minus/Solinas route as a Google-low-qubit candidate.
        const K: usize = 22;
        const GOOGLE_SCRATCH: usize = 663;
        const PACKED_STATE_SCRATCH: usize = 512;
        const INPUT_LANE_BITS: usize = 256;
        let (no_threshold_ccx, no_threshold_peak, exact_ccx, exact_peak) =
            super::super::primitive_costs::direct_solinas_multihalve_chunk_cost_split_peak(K);
        let primitive_extra = no_threshold_peak - INPUT_LANE_BITS;
        let naive_overlap_scratch = PACKED_STATE_SCRATCH + primitive_extra;
        let one_lane_reuse_scratch = naive_overlap_scratch - INPUT_LANE_BITS;
        let naive_over_google = naive_overlap_scratch as isize - GOOGLE_SCRATCH as isize;
        let one_lane_reuse_over_google =
            one_lane_reuse_scratch as isize - GOOGLE_SCRATCH as isize;
        let exact_one_lane_reuse_over_google = exact_peak as isize - GOOGLE_SCRATCH as isize;
        println!("METRIC plusminus_solinas_scale_chunk_k={K}");
        println!("METRIC plusminus_solinas_scale_chunk_no_threshold_ccx={no_threshold_ccx}");
        println!("METRIC plusminus_solinas_scale_chunk_no_threshold_peak_q={no_threshold_peak}");
        println!("METRIC plusminus_solinas_scale_chunk_exact_ccx={exact_ccx}");
        println!("METRIC plusminus_solinas_scale_chunk_exact_peak_q={exact_peak}");
        println!("METRIC plusminus_solinas_scale_chunk_primitive_extra_q={primitive_extra}");
        println!("METRIC plusminus_solinas_scale_chunk_naive_overlap_scratch={naive_overlap_scratch}");
        println!("METRIC plusminus_solinas_scale_chunk_naive_over_google_bits={naive_over_google}");
        println!("METRIC plusminus_solinas_scale_chunk_one_lane_reuse_scratch={one_lane_reuse_scratch}");
        println!("METRIC plusminus_solinas_scale_chunk_one_lane_reuse_over_google_bits={one_lane_reuse_over_google}");
        println!("METRIC plusminus_solinas_scale_chunk_exact_one_lane_reuse_over_google_bits={exact_one_lane_reuse_over_google}");
        eprintln!(
            "plus-minus Solinas scale chunk workspace: k={K}, no_threshold_ccx={no_threshold_ccx}, peak={no_threshold_peak}, primitive_extra={primitive_extra}, naive_scratch={naive_overlap_scratch}, naive_over={naive_over_google}, one_lane_reuse_scratch={one_lane_reuse_scratch}, one_lane_reuse_over={one_lane_reuse_over_google}, exact_peak={exact_peak}"
        );
        assert!(
            naive_overlap_scratch > GOOGLE_SCRATCH
                && one_lane_reuse_scratch > GOOGLE_SCRATCH
                && exact_peak > GOOGLE_SCRATCH,
            "Solinas scale chunk now fits packed plus-minus scratch; revisit scale-history route"
        );
    }

    #[test]
    fn plusminus_scaled_public_packing_map_moves_are_clifford_only() {
        // Build a deterministic slot map from the lane envelope: at each public
        // step, history bit j lives in the j-th available high slack slot across
        // all lanes.  Changing this map between steps only requires SWAP/CX
        // movement of already-classical-looking history qubits (Clifford cost),
        // but the move count estimates scheduling complexity.
        let p = SECP256K1_P;
        let samples = 8192usize;
        let mut rng = 0x5a10_6635_c11f_f00du64;
        let mut max_lane_by_step: Vec<[usize; 4]> = Vec::new();
        let mut max_hist_by_step: Vec<usize> = Vec::new();
        for _ in 0..samples {
            let mut x = rand_u256(&mut rng);
            if x.is_zero() { x = U256::from(1u64); }
            for (i, (lanes, hist)) in plusminus_scaled_lane_history_trace_for_divisor(x, p).into_iter().enumerate() {
                if i == max_lane_by_step.len() {
                    max_lane_by_step.push([0; 4]);
                    max_hist_by_step.push(0);
                }
                for j in 0..4 {
                    max_lane_by_step[i][j] = max_lane_by_step[i][j].max(lanes[j]);
                }
                max_hist_by_step[i] = max_hist_by_step[i].max(hist);
            }
        }
        let slots_for = |lanes: [usize; 4], hist: usize| -> Vec<(usize, usize)> {
            let mut slots = Vec::new();
            for lane in 0..4 {
                for bit in lanes[lane]..256 {
                    slots.push((lane, bit));
                }
            }
            assert!(slots.len() >= hist, "not enough slack slots for public packing map");
            slots.truncate(hist);
            slots
        };
        let mut prev: Vec<(usize, usize)> = Vec::new();
        let mut total_moves = 0usize;
        let mut max_step_moves = 0usize;
        let mut max_hist = 0usize;
        for i in 0..max_lane_by_step.len() {
            let cur = slots_for(max_lane_by_step[i], max_hist_by_step[i]);
            max_hist = max_hist.max(cur.len());
            let common = prev.len().min(cur.len());
            let moves = (0..common).filter(|&j| prev[j] != cur[j]).count();
            total_moves += moves;
            max_step_moves = max_step_moves.max(moves);
            prev = cur;
        }
        eprintln!(
            "plus-minus fixed public packing map: steps={}, max_hist={max_hist}, total_slot_moves={total_moves}, max_step_moves={max_step_moves}",
            max_lane_by_step.len()
        );
        println!("METRIC plusminus_scaled_packmap_steps={}", max_lane_by_step.len());
        println!("METRIC plusminus_scaled_packmap_max_history={max_hist}");
        println!("METRIC plusminus_scaled_packmap_total_slot_moves={total_moves}");
        println!("METRIC plusminus_scaled_packmap_max_step_moves={max_step_moves}");
        assert!(max_hist <= 512, "history map unexpectedly exceeds two-lane scratch budget");
    }

    fn smag_to_twos_for_plusminus_test(x: SignedMagU512ForHalfGcdTest, width: usize) -> U512 {
        let modulus = U512::from(1u64) << width;
        let mask = modulus - U512::from(1u64);
        if x.neg && !x.mag.is_zero() {
            (modulus - (x.mag & mask)) & mask
        } else {
            x.mag & mask
        }
    }

    fn twos_to_smag_for_plusminus_test(x: U512, width: usize) -> SignedMagU512ForHalfGcdTest {
        let modulus = U512::from(1u64) << width;
        let mask = modulus - U512::from(1u64);
        let x = x & mask;
        if x.bit(width - 1) {
            smag_for_halfgcd_test(true, (modulus - x) & mask)
        } else {
            smag_for_halfgcd_test(false, x)
        }
    }

    #[test]
    fn plusminus_scaled_full_state_recovers_direction_locally() {
        // The k-sequence alone has huge reverse preimage rank, but the actual
        // scaled DIV state also contains coefficient lanes.  Check the local
        // inverse relation with `(u,v,cu,cv,k)`: in each direction exactly one
        // of the new coefficient lanes should be divisible by 2^k in the way
        // required to reconstruct the old cv.  If this is unique on real
        // trajectories, direction bits need not be stored separately; reverse
        // can derive them from the full live state.
        let p = SECP256K1_P;
        let p512 = u512_from_u256_for_halfgcd_test(p);
        let samples = 512usize;
        let mut rng = 0x6635_d1ec_71a5_c0deu64;
        let mut ambiguous = 0usize;
        let mut total_steps = 0usize;
        let mut max_candidates = 0usize;
        for _ in 0..samples {
            let mut x = rand_u256(&mut rng);
            if x.is_zero() { x = U256::from(1u64); }
            let mut u = p512;
            let mut v = u512_from_u256_for_halfgcd_test(x) >> x.trailing_zeros();
            let mut cu = smag_for_halfgcd_test(false, U512::ZERO);
            let mut cv = smag_for_halfgcd_test(false, U512::from(1u64));
            if u < v {
                core::mem::swap(&mut u, &mut v);
                core::mem::swap(&mut cu, &mut cv);
            }
            while u != v {
                let old = (u, v, cu, cv);
                let mut d = u - v;
                let k = d.trailing_zeros() as usize;
                d >>= k;
                let cd = signed_add_for_halfgcd_test(cu, signed_neg_for_halfgcd_test(cv));
                let cv_scaled = smag_shl_for_plusminus_test(cv, k);
                if v >= d {
                    u = v;
                    v = d;
                    cu = cv_scaled;
                    cv = cd;
                } else {
                    u = d;
                    cu = cd;
                    cv = cv_scaled;
                }
                let new = (u, v, cu, cv);
                let mut candidates = 0usize;

                // Reverse dir=1 candidate: new=(old_v,d, old_cv<<k, old_cu-old_cv).
                if let Some(old_cv) = smag_shr_exact_for_plusminus_test(new.2, k) {
                    let old_cu = signed_add_for_halfgcd_test(new.3, old_cv);
                    let prev = (new.0 + (new.1 << k), new.0, old_cu, old_cv);
                    if prev.0 <= p512 && prev == old { candidates += 1; }
                }
                // Reverse dir=0 candidate: new=(d,old_v, old_cu-old_cv, old_cv<<k).
                if let Some(old_cv) = smag_shr_exact_for_plusminus_test(new.3, k) {
                    let old_cu = signed_add_for_halfgcd_test(new.2, old_cv);
                    let prev = (new.1 + (new.0 << k), new.1, old_cu, old_cv);
                    if prev.0 <= p512 && prev == old { candidates += 1; }
                }
                max_candidates = max_candidates.max(candidates);
                if candidates != 1 { ambiguous += 1; }
                total_steps += 1;
            }
        }
        eprintln!(
            "plus-minus scaled full-state local direction recovery: samples={samples}, steps={total_steps}, ambiguous={ambiguous}, max_candidates={max_candidates}"
        );
        println!("METRIC plusminus_scaled_direction_samples={samples}");
        println!("METRIC plusminus_scaled_direction_steps={total_steps}");
        println!("METRIC plusminus_scaled_direction_ambiguous_steps={ambiguous}");
        println!("METRIC plusminus_scaled_direction_max_candidates={max_candidates}");
        assert_eq!(ambiguous, 0, "scaled full state does not locally recover direction");
    }

    #[test]
    fn plusminus_scaled_coefficients_fit_finite_twos_complement_width() {
        // Cost probes used a 257-bit two's-complement-ish integer add/shift
        // floor.  Verify that the exact scaled coefficient recurrence matches
        // arithmetic modulo 2^W with no wrap for W=257 on sampled secp traces.
        // This is still classical, but it closes the most obvious overflow
        // objection to the controlled-shift floor.
        const WIDTH: usize = 257;
        let p = SECP256K1_P;
        let mask = (U512::from(1u64) << WIDTH) - U512::from(1u64);
        let samples = 2048usize;
        let mut rng = 0x2575_6635_7005_c0deu64;
        let mut total_steps = 0usize;
        let mut max_mag_bits = 0usize;
        for _ in 0..samples {
            let mut x = rand_u256(&mut rng);
            if x.is_zero() { x = U256::from(1u64); }
            let mut u = u512_from_u256_for_halfgcd_test(p);
            let mut v = u512_from_u256_for_halfgcd_test(x) >> x.trailing_zeros();
            let mut cu = smag_for_halfgcd_test(false, U512::ZERO);
            let mut cv = smag_for_halfgcd_test(false, U512::from(1u64));
            let mut cu_w = smag_to_twos_for_plusminus_test(cu, WIDTH);
            let mut cv_w = smag_to_twos_for_plusminus_test(cv, WIDTH);
            if u < v {
                core::mem::swap(&mut u, &mut v);
                core::mem::swap(&mut cu, &mut cv);
                core::mem::swap(&mut cu_w, &mut cv_w);
            }
            while u != v {
                let mut d = u - v;
                let k = d.trailing_zeros() as usize;
                d >>= k;
                let cd = signed_add_for_halfgcd_test(cu, signed_neg_for_halfgcd_test(cv));
                let cv_scaled = smag_shl_for_plusminus_test(cv, k);
                let cd_w = cu_w.wrapping_sub(cv_w) & mask;
                let cv_scaled_w = (cv_w << k) & mask;
                if v >= d {
                    u = v;
                    v = d;
                    cu = cv_scaled;
                    cv = cd;
                    cu_w = cv_scaled_w;
                    cv_w = cd_w;
                } else {
                    u = d;
                    cu = cd;
                    cv = cv_scaled;
                    cu_w = cd_w;
                    cv_w = cv_scaled_w;
                }
                assert_eq!(twos_to_smag_for_plusminus_test(cu_w, WIDTH), cu, "cu wrapped at width {WIDTH}");
                assert_eq!(twos_to_smag_for_plusminus_test(cv_w, WIDTH), cv, "cv wrapped at width {WIDTH}");
                max_mag_bits = max_mag_bits
                    .max(u512_bit_len_for_halfgcd_test(cu.mag))
                    .max(u512_bit_len_for_halfgcd_test(cv.mag));
                total_steps += 1;
            }
        }
        eprintln!("plus-minus finite two's-complement width: samples={samples}, steps={total_steps}, width={WIDTH}, max_mag_bits={max_mag_bits}");
        println!("METRIC plusminus_scaled_twos_width={WIDTH}");
        println!("METRIC plusminus_scaled_twos_samples={samples}");
        println!("METRIC plusminus_scaled_twos_steps={total_steps}");
        println!("METRIC plusminus_scaled_twos_max_mag_bits={max_mag_bits}");
    }

    #[test]
    fn plusminus_raw_k_live_x_parser_recompute_is_gate_dead() {
        // Last live-parser objection for the plus-minus stream: if raw k bits
        // fit only without delimiters, maybe a parser recomputes the odd-GCD
        // prefix from the live denominator around each use.  This optimistic
        // bitlength-width proxy is even larger than for centered Euclid; simple
        // prefix recomputation is not the missing raw parser.
        let p = SECP256K1_P;
        let samples = 1024usize;
        let mut rng = 0x91a7_600d_11fe_c0deu64;
        let mut weights = Vec::with_capacity(samples);
        for _ in 0..samples {
            let mut x = rand_u256(&mut rng);
            if x.is_zero() { x = U256::from(1u64); }
            let mut u = u512_from_u256_for_halfgcd_test(p);
            let mut v = u512_from_u256_for_halfgcd_test(x);
            let initial_twos = x.trailing_zeros() as usize;
            v >>= initial_twos;
            if u < v {
                core::mem::swap(&mut u, &mut v);
            }
            let mut prefix = usize_bit_len_for_payload_test(initial_twos) * 256usize;
            let mut total = 0usize;
            while u != v {
                let mut d = u - v;
                let k = d.trailing_zeros() as usize;
                prefix += usize_bit_len_for_payload_test(k) * u512_bit_len_for_halfgcd_test(u).max(1);
                total += 2 * prefix;
                d >>= k;
                if v >= d {
                    u = v;
                    v = d;
                } else {
                    u = d;
                }
            }
            weights.push(total);
        }
        weights.sort_unstable();
        let mean = weights.iter().sum::<usize>() as f64 / samples as f64;
        let p99 = weights[samples * 99 / 100];
        eprintln!("plus-minus raw-k live-x parser recompute weight: mean={mean:.1}, p99={p99}");
        println!("METRIC plusminus_kseq_live_recompute_weight_mean={mean:.3}");
        println!("METRIC plusminus_kseq_live_recompute_weight_p99={p99}");
        assert!(mean > 8_000_000.0);
    }

    #[test]
    fn plusminus_raw_k_rank_decoder_is_dense() {
        // The clever rescue for plus-minus is to concatenate raw binary k values
        // and store only a tiny rank among the valid parses.  Information-wise
        // this is tempting: toy max multiplicity is tiny and secp scratch would
        // fit if the rank decoder were local.  But the rank bit is a global
        // parsing function of x; its ANF is already maximal/half-dense on toy
        // fields.  This mirrors the rolling-hash Kaliski lesson: compressed
        // history without a cheap branch-pop decoder is not a reversible DIV.
        let cases = [(8usize, 251u16), (10, 1021), (12, 4093), (14, 16381)];
        for &(n, p) in &cases {
            let (degree, density, max_mult) = plusminus_raw_k_rank_anf_stats(n, p);
            let table = 1usize << n;
            eprintln!(
                "plus-minus raw-k rank ANF: n={n}, degree={degree}, density={density}/{table}, max_multiplicity={max_mult}"
            );
            if n == 14 {
                println!("METRIC plusminus_rawk_rank_degree_n14={degree}");
                println!("METRIC plusminus_rawk_rank_density_n14={density}");
                println!("METRIC plusminus_rawk_rank_max_multiplicity_n14={max_mult}");
            }
            assert!(degree + 1 >= n);
            assert!(density > table / 3);
        }
    }

    #[test]
    fn centered_euclid_raw_stream_fits_but_parser_entropy_does_not() {
        // Replace ordinary Euclid by a signed/centered remainder step using the
        // nearest quotient.  Signs are derivable from the signed residual pair,
        // and the absolute quotients are much smaller: raw magnitude payload is
        // below the 600-scratch line when paired with one 256-bit data register.
        // Unfortunately that is not a self-contained reversible stream.  As
        // soon as we charge even one boundary bit per quotient, or an empirical
        // prefix-code length for the quotient alphabet, the parser state is back
        // above the budget.  This is a sharper version of the quotient-stream
        // lesson: centered quotients are interesting only if a live-state parser
        // can consume raw magnitude bits without separate denominator work regs.
        use std::collections::BTreeMap;
        let p = SECP256K1_P;
        let samples = 8192usize;
        let mut rng = 0xced0_e0c1_1d5e_5eedu64;
        let mut seqs = Vec::with_capacity(samples);
        let mut freq: BTreeMap<U512, usize> = BTreeMap::new();
        let mut total = 0usize;
        let mut raw_payloads = Vec::with_capacity(samples);
        let mut counts = Vec::with_capacity(samples);
        for _ in 0..samples {
            let mut x = rand_u256(&mut rng);
            if x.is_zero() { x = U256::from(1u64); }
            let qs = centered_euclid_abs_quotients_for_divisor(x, p);
            let raw = qs.iter().map(|&q| u512_bit_len_for_halfgcd_test(q)).sum::<usize>();
            for &q in &qs {
                *freq.entry(q).or_insert(0) += 1;
                total += 1;
            }
            counts.push(qs.len());
            raw_payloads.push(raw);
            seqs.push(qs);
        }
        raw_payloads.sort_unstable();
        counts.sort_unstable();
        let p99 = samples * 99 / 100;
        let raw_p99 = raw_payloads[p99];
        let count_p99 = counts[p99];
        let boundary_scratch_p99 = 256 + raw_p99 + count_p99;
        let log_total = (total as f64).log2();
        let mut entropy_lengths = Vec::with_capacity(samples);
        for qs in &seqs {
            let mut bits = 0.0f64;
            for &q in qs {
                let f = *freq.get(&q).unwrap() as f64;
                bits += log_total - f.log2();
            }
            entropy_lengths.push(bits);
        }
        entropy_lengths.sort_by(|a, b| a.partial_cmp(b).unwrap());
        let entropy_p99 = entropy_lengths[p99];
        let entropy_scratch_p99 = 256.0 + entropy_p99;
        eprintln!(
            "centered Euclid quotients: raw_p99={raw_p99}, count_p99={count_p99}, boundary_scratch_p99={boundary_scratch_p99}, entropy_scratch_p99={entropy_scratch_p99:.1}"
        );
        println!("METRIC centered_euclid_raw_payload_p99={raw_p99}");
        println!("METRIC centered_euclid_raw_scratch_p99={}", 256 + raw_p99);
        println!("METRIC centered_euclid_boundary_scratch_p99={boundary_scratch_p99}");
        println!("METRIC centered_euclid_entropy_scratch_p99={entropy_scratch_p99:.3}");
        assert!(256 + raw_p99 < 600, "raw centered quotient magnitudes should be tantalizing");
        assert!(boundary_scratch_p99 > 700, "boundary bits should kill self-contained raw packing");
        assert!(entropy_scratch_p99 > 690.0, "empirical prefix-code parser should still exceed scratch");
    }

    #[test]
    fn centered_euclid_live_x_parser_recompute_still_gate_dead() {
        // The only possible rescue for the raw centered stream is a parser that
        // uses the live denominator x to infer quotient boundaries.  The naive
        // reversible version recomputes the centered Euclid prefix from x around
        // every quotient use.  Even with the much smaller centered quotients,
        // the optimistic bitlength*width proxy is still millions of controlled
        // trials for one DIV, so the parser cannot be a simple live-x replay.
        let p = SECP256K1_P;
        let samples = 1024usize;
        let mut rng = 0xc0de_17e0_c1d5_eedu64;
        let mut weights = Vec::with_capacity(samples);
        for _ in 0..samples {
            let mut x = rand_u256(&mut rng);
            if x.is_zero() { x = U256::from(1u64); }
            let mut u = smag_for_halfgcd_test(false, u512_from_u256_for_halfgcd_test(p));
            let mut v = smag_for_halfgcd_test(false, u512_from_u256_for_halfgcd_test(x));
            let mut prefix = 0usize;
            let mut total = 0usize;
            while !v.mag.is_zero() {
                let q = ((u.mag << 1usize) + v.mag) / (v.mag << 1usize);
                let q_bits = u512_bit_len_for_halfgcd_test(q);
                prefix += q_bits * u512_bit_len_for_halfgcd_test(u.mag).max(1);
                total += 2 * prefix;
                let q_neg = u.neg ^ v.neg;
                let qv = signed_mul_mag_for_halfgcd_test(v, q_neg, q);
                let r = signed_add_for_halfgcd_test(u, signed_neg_for_halfgcd_test(qv));
                u = v;
                v = r;
            }
            weights.push(total);
        }
        weights.sort_unstable();
        let mean = weights.iter().sum::<usize>() as f64 / samples as f64;
        let p99 = weights[samples * 99 / 100];
        eprintln!("centered Euclid live-x parser recompute weight: mean={mean:.1}, p99={p99}");
        println!("METRIC centered_euclid_live_recompute_weight_mean={mean:.3}");
        println!("METRIC centered_euclid_live_recompute_weight_p99={p99}");
        assert!(mean > 5_000_000.0);
    }

    #[test]
    fn half_gcd_checkpoint_matrix_mbu_phase_is_dense_too() {
        // If the first half-GCD matrix is too large to carry with the tail, a
        // natural kickmix thought is to X-measure the matrix checkpoint and
        // phase-correct it from the original denominator x.  A representative
        // parity of the checkpoint matrix is already high-degree/half-dense on
        // toy fields, so matrix checkpoints are not a free MBUC object either.
        let cases = [
            (8usize, 251u16, 0b1010_0101u16),
            (10usize, 1021u16, 0b10_1001_0101u16),
            (12usize, 4093u16, 0b1010_0101_0101u16),
            (14usize, 16381u16, 0b10_1010_0101_0101u16),
        ];
        for &(n, p, mask) in &cases {
            let (degree, density) = half_gcd_matrix_parity_anf_stats(n, p, mask);
            let table = 1usize << n;
            eprintln!(
                "half-GCD checkpoint matrix parity ANF: n={n}, p={p}, degree={degree}, density={density}/{table}"
            );
            if n == 14 {
                println!("METRIC halfgcd_matrix_mbu_degree_n14={degree}");
                println!("METRIC halfgcd_matrix_mbu_density_n14={density}");
            }
            assert!(degree + 1 >= n);
            assert!(density > table / 4);
        }
    }

    #[test]
    fn quotient_stream_division_is_algebraically_good_but_packing_blocks_scratch600() {
        // Ground-up DIV attempt, independent of Kaliski/BY microsteps:
        // compute the ordinary Euclidean quotient stream of (p,x), uncompute
        // the denominator pass, then replay the quotient matrices on
        // (r,s)=(0,y).  Algebraically this is beautiful: the data row ends as
        // (y/x,0), so after a swap it is exactly an in-place division.  The
        // scratch accounting is also tantalizing: denominator generation needs
        // one 256-bit u-register plus the quotient stream, and coefficient
        // replay needs one 256-bit r-register plus the same stream.
        //
        // The catch is that the quotient stream is variable-length.  The raw
        // payload is already right at the 600-scratch edge, and any reversible
        // self-delimiting/pointer scheme pushes it over.  Without a cheap
        // stack/packing primitive this becomes another hidden history channel,
        // not a local DIV circuit.
        let p = SECP256K1_P;
        let mut rng = 0x1234_5678_9abc_def0u64;
        for _ in 0..200 {
            let mut x = rand_u256(&mut rng);
            if x.is_zero() { x = U256::from(1u64); }
            let y = rand_u256(&mut rng);
            let (q, z, _qs) = replay_euclid_quotient_division(x, y, p);
            assert!(z.is_zero());
            assert_eq!(q, y.mul_mod(x.inv_mod(p).unwrap(), p));
        }

        let samples = 4096usize;
        let mut payload_bits = Vec::with_capacity(samples);
        let mut one_boundary_bit_bits = Vec::with_capacity(samples);
        let mut counts = Vec::with_capacity(samples);
        let mut longdiv_weight = Vec::with_capacity(samples);
        for _ in 0..samples {
            let mut x = rand_u256(&mut rng);
            if x.is_zero() { x = U256::from(1u64); }
            let mut u = p;
            let mut v = x;
            let mut payload = 0usize;
            let mut count = 0usize;
            let mut weighted_trials = 0usize;
            while !v.is_zero() {
                let q = u / v;
                let q_bits = u256_bit_len(q);
                payload += q_bits;
                count += 1;
                weighted_trials += q_bits * u256_bit_len(u);
                let rem = u - q * v;
                u = v;
                v = rem;
            }
            payload_bits.push(payload);
            counts.push(count);
            // Unrealistically optimistic packing model: raw quotient payload
            // plus only one boundary bit per quotient.  A real prefix/rank
            // code costs more, so if even this misses scratch the dynamic
            // stream is not locally solved.
            one_boundary_bit_bits.push(payload + count);
            longdiv_weight.push(weighted_trials);
        }
        payload_bits.sort_unstable();
        one_boundary_bit_bits.sort_unstable();
        counts.sort_unstable();
        longdiv_weight.sort_unstable();
        let p99 = samples * 99 / 100;
        let payload_mean = payload_bits.iter().sum::<usize>() as f64 / samples as f64;
        let longdiv_mean = longdiv_weight.iter().sum::<usize>() as f64 / samples as f64;
        let payload_p99 = payload_bits[p99];
        let payload_max = *payload_bits.last().unwrap();
        let count_p99 = counts[p99];
        let one_boundary_p99 = one_boundary_bit_bits[p99];
        let longdiv_p99 = longdiv_weight[p99];
        let raw_scratch_max = 256 + payload_max;
        let one_boundary_scratch_p99 = 256 + one_boundary_p99;
        eprintln!(
            "Euclid quotient DIV stream: payload_mean={payload_mean:.1}, payload_p99={payload_p99}, payload_max={payload_max}, count_p99={count_p99}, one_boundary_p99={one_boundary_p99}, longdiv_mean={longdiv_mean:.1}, longdiv_p99={longdiv_p99}, raw_scratch_max={raw_scratch_max}, one_boundary_scratch_p99={one_boundary_scratch_p99}"
        );
        println!("METRIC euclid_div_replay_samples=200");
        println!("METRIC euclid_quotient_payload_mean_bits={payload_mean:.3}");
        println!("METRIC euclid_quotient_payload_p99_bits={payload_p99}");
        println!("METRIC euclid_quotient_payload_max_bits={payload_max}");
        println!("METRIC euclid_quotient_count_p99={count_p99}");
        println!("METRIC euclid_quotient_raw_scratch_max={raw_scratch_max}");
        println!("METRIC euclid_quotient_one_boundary_scratch_p99={one_boundary_scratch_p99}");
        println!("METRIC euclid_longdiv_weight_mean={longdiv_mean:.3}");
        println!("METRIC euclid_longdiv_weight_p99={longdiv_p99}");
        assert!(payload_p99 < 360, "payload should stay close to the 344-bit sidecar target");
        assert!(raw_scratch_max > 600, "raw quotient payload unexpectedly fits worst sampled scratch");
        assert!(one_boundary_scratch_p99 > 760, "even one-boundary-bit quotient packing unexpectedly fits scratch");
    }

    #[test]
    fn euclid_quotient_stream_is_a_3m_candidate_only_with_stored_parser_budget() {
        // Revisit the ordinary quotient stream under the user's relaxed
        // question: <3M while staying under the project qubit cap, not the
        // strict Google ~600-scratch regime.  The old blocker was parser
        // scratch (one-boundary p99 ~= 776), which is fatal for 1175q but not
        // obviously fatal for the current <=2800q cap.  This is deliberately a
        // lower-bound ledger, not a solved circuit: q extraction, controlled
        // q*s replay, exact boundary cleanup, and phase cleanliness remain the
        // hard pieces.
        let p = SECP256K1_P;
        let samples = 4096usize;
        let mut rng = 0x2800_3e0c_11d6_0001u64;
        let mut payload_bits = Vec::with_capacity(samples);
        let mut one_boundary_bits = Vec::with_capacity(samples);
        let mut counts = Vec::with_capacity(samples);
        let mut longdiv_weight = Vec::with_capacity(samples);
        for _ in 0..samples {
            let mut x = rand_u256(&mut rng);
            if x.is_zero() { x = U256::from(1u64); }
            let mut u = p;
            let mut v = x;
            let mut payload = 0usize;
            let mut count = 0usize;
            let mut weighted_trials = 0usize;
            while !v.is_zero() {
                let q = u / v;
                let q_bits = u256_bit_len(q);
                payload += q_bits;
                count += 1;
                weighted_trials += q_bits * u256_bit_len(u);
                let rem = u - q * v;
                u = v;
                v = rem;
            }
            payload_bits.push(payload);
            one_boundary_bits.push(payload + count);
            counts.push(count);
            longdiv_weight.push(weighted_trials);
        }
        payload_bits.sort_unstable();
        one_boundary_bits.sort_unstable();
        counts.sort_unstable();
        longdiv_weight.sort_unstable();
        let p99 = samples * 99 / 100;
        let payload_p99 = payload_bits[p99];
        let payload_max = *payload_bits.last().unwrap();
        let count_p99 = counts[p99];
        let one_boundary_p99 = one_boundary_bits[p99];
        let longdiv_p99 = longdiv_weight[p99];

        let scaffold_after_div = 642_716isize;
        let schoolbook_mul_add = 150_145usize;
        let per_qbit_replay_ccx = schoolbook_mul_add.div_ceil(256);
        let coeff_replay_per_div = payload_p99 * per_qbit_replay_ccx;
        let longdiv_unit_ccx = 8usize; // optimistic comparator/subtract bit-trial budget.
        let longdiv_compute_uncompute_per_div = 2 * longdiv_weight[p99] * longdiv_unit_ccx;
        let one_div_projected = coeff_replay_per_div + longdiv_compute_uncompute_per_div;
        let two_div_projected = 2 * one_div_projected;
        let pointadd_projected = scaffold_after_div + two_div_projected as isize;
        let gap_to_3m = pointadd_projected - 3_000_000isize;
        let longdiv_unit_budget_for_3m = (3_000_000isize - scaffold_after_div - 2 * coeff_replay_per_div as isize) as f64
            / (4.0 * longdiv_p99 as f64);
        let scratch_beyond_txty_p99 = 256 + one_boundary_p99;
        let conservative_peak_with_512_workspace = 512 + scratch_beyond_txty_p99 + 512;
        println!("METRIC euclid_2800_payload_p99_bits={payload_p99}");
        println!("METRIC euclid_2800_payload_max_bits={payload_max}");
        println!("METRIC euclid_2800_count_p99={count_p99}");
        println!("METRIC euclid_2800_one_boundary_scratch_p99={scratch_beyond_txty_p99}");
        println!("METRIC euclid_2800_longdiv_weight_p99={longdiv_p99}");
        println!("METRIC euclid_2800_per_qbit_replay_ccx={per_qbit_replay_ccx}");
        println!("METRIC euclid_2800_one_div_projected_ccx={one_div_projected}");
        println!("METRIC euclid_2800_projected_gap_to_3m_ccx={gap_to_3m}");
        println!("METRIC euclid_2800_longdiv_unit_budget_for_3m_ccx={longdiv_unit_budget_for_3m:.3}");
        println!("METRIC euclid_2800_conservative_peak_qubits={conservative_peak_with_512_workspace}");
        eprintln!(
            "Euclid quotient 2800q/3M ledger: payload_p99={payload_p99}, count_p99={count_p99}, scratch_p99={scratch_beyond_txty_p99}, longdiv_p99={longdiv_p99}, one_div={one_div_projected}, pointadd={pointadd_projected}, gap3m={gap_to_3m}, unit_budget={longdiv_unit_budget_for_3m:.2}, peak≈{conservative_peak_with_512_workspace}"
        );
        assert!(scratch_beyond_txty_p99 > 663, "stored quotient stream unexpectedly fits Google scratch; promote harder");
        assert!(conservative_peak_with_512_workspace < 2800, "stored quotient stream is too wide even for current cap");
        assert!(gap_to_3m < 0, "even optimistic stored-parser quotient stream misses 3M; demote for relaxed target too");
        assert!(longdiv_unit_budget_for_3m > 6.0, "long-division bit-trial budget is implausibly tight");
    }

    #[test]
    fn euclid_stored_parser_needs_dynamic_longdivision_not_fixed_scan() {
        // Adversarial follow-up to the relaxed-2800q quotient-stream ledger.
        // The attractive 2.51M estimate used a bitlength-aware weighted-trial
        // count (~45k p99).  A reversible circuit cannot literally run a
        // data-dependent loop for free.  If quotient extraction scans all 256
        // possible shifts for every Euclid quotient, the static comparator
        // surface is count*256*256 bit-trials and the route is immediately
        // dead even at one CCX per bit-trial.
        let p = SECP256K1_P;
        let samples = 4096usize;
        let mut rng = 0x2800_f15c_5cae_0001u64;
        let mut payload_bits = Vec::with_capacity(samples);
        let mut counts = Vec::with_capacity(samples);
        let mut weighted_trials = Vec::with_capacity(samples);
        let mut fixed_scan_trials = Vec::with_capacity(samples);
        for _ in 0..samples {
            let mut x = rand_u256(&mut rng);
            if x.is_zero() { x = U256::from(1u64); }
            let mut u = p;
            let mut v = x;
            let mut payload = 0usize;
            let mut count = 0usize;
            let mut weighted = 0usize;
            while !v.is_zero() {
                let q = u / v;
                let q_bits = u256_bit_len(q);
                payload += q_bits;
                count += 1;
                weighted += q_bits * u256_bit_len(u);
                let rem = u - q * v;
                u = v;
                v = rem;
            }
            payload_bits.push(payload);
            counts.push(count);
            weighted_trials.push(weighted);
            fixed_scan_trials.push(count * 256usize * 256usize);
        }
        payload_bits.sort_unstable();
        counts.sort_unstable();
        weighted_trials.sort_unstable();
        fixed_scan_trials.sort_unstable();
        let p99 = samples * 99 / 100;
        let payload_p99 = payload_bits[p99];
        let count_p99 = counts[p99];
        let weighted_p99 = weighted_trials[p99];
        let fixed_scan_p99 = fixed_scan_trials[p99];
        let per_qbit_replay_ccx = 587usize;
        let coeff_replay_per_div = payload_p99 * per_qbit_replay_ccx;
        let scaffold_after_div = 642_716isize;
        let fixed_scan_one_ccx_pointadd = scaffold_after_div
            + 2 * (coeff_replay_per_div as isize + 2 * fixed_scan_p99 as isize);
        let fixed_scan_gap = fixed_scan_one_ccx_pointadd - 3_000_000isize;
        let fixed_scan_unit_budget = (3_000_000isize - scaffold_after_div - 2 * coeff_replay_per_div as isize) as f64
            / (4.0 * fixed_scan_p99 as f64);
        let dynamic_vs_fixed_ratio = fixed_scan_p99 as f64 / weighted_p99 as f64;
        println!("METRIC euclid_fixedscan_count_p99={count_p99}");
        println!("METRIC euclid_fixedscan_payload_p99_bits={payload_p99}");
        println!("METRIC euclid_fixedscan_weighted_trials_p99={weighted_p99}");
        println!("METRIC euclid_fixedscan_static_trials_p99={fixed_scan_p99}");
        println!("METRIC euclid_fixedscan_dynamic_vs_fixed_ratio={dynamic_vs_fixed_ratio:.3}");
        println!("METRIC euclid_fixedscan_gap_to_3m_at_1ccx={fixed_scan_gap}");
        println!("METRIC euclid_fixedscan_unit_budget_for_3m_ccx={fixed_scan_unit_budget:.6}");
        eprintln!(
            "Euclid fixed-scan risk: count_p99={count_p99}, weighted_p99={weighted_p99}, fixed_scan_p99={fixed_scan_p99}, ratio={dynamic_vs_fixed_ratio:.1}, gap_at_1ccx={fixed_scan_gap}, unit_budget={fixed_scan_unit_budget:.6}"
        );
        assert!(fixed_scan_gap > 20_000_000, "fixed-scan long division might fit; revisit quotient extractor");
        assert!(fixed_scan_unit_budget < 0.1, "fixed-scan unit budget is not impossibly small; measure circuit");
    }

    #[test]
    fn euclid_packed_extractor_has_only_small_alignment_budget() {
        // If the fixed scan is dead, the only remaining quotient-stream hope is
        // a packed extractor that iterates over quotient payload bits.  This
        // ledger estimates the budget for the missing alignment mechanism.  It
        // is tight: after paying one compare/subtract per payload bit and one
        // leading-bit scan per quotient, only about 1k CCX/quotient remains for
        // aligning v<<shift.  A generic log-depth quantum barrel shift would
        // consume that margin; a metadata/offset comparator would be needed.
        let payload_p99 = 349usize;
        let count_p99 = 173usize;
        let scaffold_after_div = 642_716isize;
        let per_qbit_replay_ccx = 587usize;
        let coeff_replay_per_div = payload_p99 * per_qbit_replay_ccx;
        let extraction_roundtrip_budget_per_div = ((3_000_000isize - scaffold_after_div) / 2) as isize
            - coeff_replay_per_div as isize;
        let extraction_oneway_budget = extraction_roundtrip_budget_per_div / 2;
        let n = 256usize;
        let compare_sub_per_payload_bit = 3 * n; // compare + masked subtract, optimistic.
        let payload_floor = payload_p99 * compare_sub_per_payload_bit;
        let leading_scan_floor = count_p99 * n;
        let remaining_alignment_oneway = extraction_oneway_budget - payload_floor as isize - leading_scan_floor as isize;
        let alignment_budget_per_quotient = remaining_alignment_oneway as f64 / count_p99 as f64;
        let log_barrel_per_quotient = n * 8; // one Toffoli/bit/layer toy floor for a generic barrel.
        let log_barrel_gap_oneway = (log_barrel_per_quotient * count_p99) as isize - remaining_alignment_oneway;
        let log_barrel_pointadd_gap = 2 * 2 * log_barrel_gap_oneway;
        println!("METRIC euclid_packed_extraction_oneway_budget_ccx={extraction_oneway_budget}");
        println!("METRIC euclid_packed_payload_floor_ccx={payload_floor}");
        println!("METRIC euclid_packed_leading_scan_floor_ccx={leading_scan_floor}");
        println!("METRIC euclid_packed_alignment_budget_per_quotient_ccx={alignment_budget_per_quotient:.3}");
        println!("METRIC euclid_packed_log_barrel_gap_pointadd_ccx={log_barrel_pointadd_gap}");
        eprintln!(
            "Euclid packed extractor alignment budget: one_way_budget={extraction_oneway_budget}, payload_floor={payload_floor}, leading_floor={leading_scan_floor}, align_budget_per_q={alignment_budget_per_quotient:.1}, log_barrel_pointadd_gap={log_barrel_pointadd_gap}"
        );
        assert!(alignment_budget_per_quotient > 500.0, "no room even for metadata alignment; quotient stream dead");
        assert!(alignment_budget_per_quotient < log_barrel_per_quotient as f64, "generic barrel alignment might fit; build it");
    }

    #[test]
    fn centered_euclid_relaxed_2800q_has_same_packed_extractor_risk() {
        // Centered quotients improve the ordinary quotient-stream shape for the
        // relaxed 3M/current-qubit target.  This remains speculative because a
        // fixed scan is still dead, but unlike ordinary Euclid the packed
        // extractor has several thousand CCX/quotient left for alignment.
        let p = SECP256K1_P;
        let samples = 4096usize;
        let mut rng = 0x2800_ce0c_11d6_0002u64;
        let mut payload_bits = Vec::with_capacity(samples);
        let mut one_boundary_bits = Vec::with_capacity(samples);
        let mut counts = Vec::with_capacity(samples);
        let mut weighted_trials = Vec::with_capacity(samples);
        let mut fixed_scan_trials = Vec::with_capacity(samples);
        for _ in 0..samples {
            let mut x = rand_u256(&mut rng);
            if x.is_zero() { x = U256::from(1u64); }
            let mut u = smag_for_halfgcd_test(false, u512_from_u256_for_halfgcd_test(p));
            let mut v = smag_for_halfgcd_test(false, u512_from_u256_for_halfgcd_test(x));
            let mut payload = 0usize;
            let mut count = 0usize;
            let mut weighted = 0usize;
            while !v.mag.is_zero() {
                let numerator = (u.mag << 1usize) + v.mag;
                let denominator = v.mag << 1usize;
                let q = numerator / denominator;
                let q_bits = u512_bit_len_for_halfgcd_test(q).max(1);
                payload += q_bits;
                count += 1;
                weighted += q_bits * u512_bit_len_for_halfgcd_test(u.mag).max(u512_bit_len_for_halfgcd_test(v.mag));
                let q_neg = u.neg ^ v.neg;
                let qv = signed_mul_mag_for_halfgcd_test(v, q_neg, q);
                let r = signed_add_for_halfgcd_test(u, signed_neg_for_halfgcd_test(qv));
                u = v;
                v = r;
            }
            assert_eq!(u.mag, U512::from(1u64));
            payload_bits.push(payload);
            one_boundary_bits.push(payload + count);
            counts.push(count);
            weighted_trials.push(weighted);
            fixed_scan_trials.push(count * 256usize * 256usize);
        }
        payload_bits.sort_unstable();
        one_boundary_bits.sort_unstable();
        counts.sort_unstable();
        weighted_trials.sort_unstable();
        fixed_scan_trials.sort_unstable();
        let p99 = samples * 99 / 100;
        let payload_p99 = payload_bits[p99];
        let payload_max = *payload_bits.last().unwrap();
        let count_p99 = counts[p99];
        let one_boundary_scratch_p99 = 256 + one_boundary_bits[p99];
        let weighted_p99 = weighted_trials[p99];
        let fixed_scan_p99 = fixed_scan_trials[p99];
        let per_qbit_replay_ccx = 587usize;
        let coeff_replay_per_div = payload_p99 * per_qbit_replay_ccx;
        let scaffold_after_div = 642_716isize;
        let one_div_weighted = coeff_replay_per_div + 2 * weighted_p99 * 8usize;
        let pointadd_weighted = scaffold_after_div + 2 * one_div_weighted as isize;
        let weighted_gap = pointadd_weighted - 3_000_000isize;
        let fixed_scan_gap = scaffold_after_div + 2 * (coeff_replay_per_div as isize + 2 * fixed_scan_p99 as isize) - 3_000_000isize;
        let extraction_roundtrip_budget_per_div = ((3_000_000isize - scaffold_after_div) / 2) as isize
            - coeff_replay_per_div as isize;
        let extraction_oneway_budget = extraction_roundtrip_budget_per_div / 2;
        let payload_floor = payload_p99 * 3usize * 256usize;
        let leading_scan_floor = count_p99 * 256usize;
        let align_remaining = extraction_oneway_budget - payload_floor as isize - leading_scan_floor as isize;
        let align_budget_per_q = align_remaining as f64 / count_p99 as f64;
        let log_barrel_per_quotient = 256usize * 8usize;
        let log_barrel_gap_oneway = (log_barrel_per_quotient * count_p99) as isize - align_remaining;
        let log_barrel_gap_pointadd = 4 * log_barrel_gap_oneway;
        println!("METRIC centered_2800_payload_p99_bits={payload_p99}");
        println!("METRIC centered_2800_payload_max_bits={payload_max}");
        println!("METRIC centered_2800_count_p99={count_p99}");
        println!("METRIC centered_2800_one_boundary_scratch_p99={one_boundary_scratch_p99}");
        println!("METRIC centered_2800_weighted_trials_p99={weighted_p99}");
        println!("METRIC centered_2800_projected_gap_to_3m_ccx={weighted_gap}");
        println!("METRIC centered_2800_fixedscan_gap_to_3m_at_1ccx={fixed_scan_gap}");
        println!("METRIC centered_2800_extraction_oneway_budget_ccx={extraction_oneway_budget}");
        println!("METRIC centered_2800_alignment_budget_per_quotient_ccx={align_budget_per_q:.3}");
        println!("METRIC centered_2800_log_barrel_gap_pointadd_ccx={log_barrel_gap_pointadd}");
        eprintln!(
            "Centered Euclid relaxed ledger: payload_p99={payload_p99}, count_p99={count_p99}, scratch={one_boundary_scratch_p99}, weighted_p99={weighted_p99}, gap3m={weighted_gap}, fixed_gap={fixed_scan_gap}, oneway_budget={extraction_oneway_budget}, align_budget_per_q={align_budget_per_q:.1}, log_barrel_gap={log_barrel_gap_pointadd}"
        );
        assert!(weighted_gap < 0, "centered weighted ledger misses relaxed 3M; demote it too");
        assert!(one_boundary_scratch_p99 > 663, "centered parser unexpectedly fits Google scratch");
        assert!(fixed_scan_gap > 20_000_000, "fixed scan is not dead for centered Euclid; revisit");
        assert!(align_budget_per_q > 1_000.0, "centered packed extractor has too little alignment budget");
        assert!(log_barrel_gap_pointadd > 0, "generic log barrel fits the centered 3M budget; prototype it directly");
    }

    #[test]
    fn centered_euclid_fixed_k_public_shift_slots_are_not_enough() {
        // Possible escape from variable-offset alignment: store each quotient in
        // a fixed K-bit slot, so the K compare/subtract shifts are public and no
        // barrel/offset mux is needed.  This trades alignment for many unused
        // q-bit slots.  The budget/failure tradeoff is bad: K small enough to
        // fit 3M misses many samples; K large enough to cover quotient tails is
        // over budget even before cleanup details.
        let p = SECP256K1_P;
        let samples = 32_768usize;
        let mut rng = 0x2800_f17e_5107_0001u64;
        let ks = [4usize, 5, 6, 8, 10, 12];
        let mut fail = [0usize; 6];
        let mut counts = Vec::with_capacity(samples);
        let mut max_qbits_seen = 0usize;
        for _ in 0..samples {
            let mut x = rand_u256(&mut rng);
            if x.is_zero() { x = U256::from(1u64); }
            let qs = centered_euclid_abs_quotients_for_divisor(x, p);
            counts.push(qs.len());
            let sample_max_qbits = qs
                .iter()
                .map(|q| u512_bit_len_for_halfgcd_test(*q).max(1))
                .max()
                .unwrap_or(1);
            max_qbits_seen = max_qbits_seen.max(sample_max_qbits);
            for (i, &k) in ks.iter().enumerate() {
                if sample_max_qbits > k {
                    fail[i] += 1;
                }
            }
        }
        counts.sort_unstable();
        let count_p99 = counts[samples * 99 / 100];
        let count_p999 = counts[samples * 999 / 1000];
        let count_max = *counts.last().unwrap();
        let c_records = count_p999;
        let scaffold_after_div = 642_716isize;
        let per_qbit_replay_ccx = 587usize;
        let compare_sub_per_slot = 3usize * 256usize;
        let per_record_boundary_floor = 256usize;
        let mut best_exactish_k = 0usize;
        let mut best_exactish_gap = isize::MAX;
        for (i, &k) in ks.iter().enumerate() {
            let qslots = c_records * k;
            let coeff = qslots * per_qbit_replay_ccx;
            let extraction_oneway = qslots * compare_sub_per_slot + c_records * per_record_boundary_floor;
            let pointadd = scaffold_after_div + 2 * (coeff as isize + 2 * extraction_oneway as isize);
            let gap = pointadd - 3_000_000isize;
            let fail_ppm = fail[i] * 1_000_000usize / samples;
            println!("METRIC centered_fixedk{k}_fail_ppm={fail_ppm}");
            println!("METRIC centered_fixedk{k}_gap_to_3m_ccx={gap}");
            if fail_ppm == 0 && gap < best_exactish_gap {
                best_exactish_gap = gap;
                best_exactish_k = k;
            }
        }
        println!("METRIC centered_fixedk_count_p99={count_p99}");
        println!("METRIC centered_fixedk_count_p999={count_p999}");
        println!("METRIC centered_fixedk_count_max={count_max}");
        println!("METRIC centered_fixedk_max_qbits_seen={max_qbits_seen}");
        println!("METRIC centered_fixedk_best_zero_fail_k={best_exactish_k}");
        println!("METRIC centered_fixedk_best_zero_fail_gap_ccx={best_exactish_gap}");
        eprintln!(
            "Centered fixed-K slots: count_p99={count_p99}, count_p999={count_p999}, count_max={count_max}, max_qbits={max_qbits_seen}, best_zero_fail_k={best_exactish_k}, best_zero_fail_gap={best_exactish_gap}, fail={fail:?}"
        );
        assert!(fail[0] > samples / 100, "K=4 fixed slots are accurate enough; revisit public-shift extraction");
        assert!(best_exactish_gap > 0, "a zero-fail fixed-K slot plan fits 3M; prototype it");
    }

    #[test]
    fn centered_euclid_restoring_subtract_plus_barrel_reopens_relaxed_3m_budget() {
        // The previous packed-extractor budget used a 3n compare+masked-sub
        // floor.  Long division can instead use a restoring subtract: subtract
        // shifted v, record the borrow as the quotient bit, and add back only on
        // borrow.  At the static-Toffoli level this is closer to 2n per q slot.
        // With centered quotients, that is enough to pay for a generic n log n
        // variable barrel in the relaxed 3M/2800q model.  This is a candidate
        // ledger, not a circuit proof; the next hard piece is a phase-clean toy
        // restoring-subtract + variable-shift extractor.
        let p = SECP256K1_P;
        let samples = 4096usize;
        let mut rng = 0x2800_ce0c_2a15_0001u64;
        let mut payload_bits = Vec::with_capacity(samples);
        let mut one_boundary_bits = Vec::with_capacity(samples);
        let mut counts = Vec::with_capacity(samples);
        for _ in 0..samples {
            let mut x = rand_u256(&mut rng);
            if x.is_zero() { x = U256::from(1u64); }
            let qs = centered_euclid_abs_quotients_for_divisor(x, p);
            let payload = qs
                .iter()
                .map(|q| u512_bit_len_for_halfgcd_test(*q).max(1))
                .sum::<usize>();
            payload_bits.push(payload);
            one_boundary_bits.push(payload + qs.len());
            counts.push(qs.len());
        }
        payload_bits.sort_unstable();
        one_boundary_bits.sort_unstable();
        counts.sort_unstable();
        let p99 = samples * 99 / 100;
        let payload_p99 = payload_bits[p99];
        let count_p99 = counts[p99];
        let scratch_p99 = 256 + one_boundary_bits[p99];
        let scaffold_after_div = 642_716isize;
        let per_qbit_replay_ccx = 587usize;
        let coeff_replay_per_div = payload_p99 * per_qbit_replay_ccx;
        let restoring_sub_per_qbit = 2usize * 256usize;
        let generic_barrel_per_quotient = 256usize * 8usize;
        let leading_scan_per_quotient = 256usize;
        let extraction_oneway = payload_p99 * restoring_sub_per_qbit
            + count_p99 * (generic_barrel_per_quotient + leading_scan_per_quotient);
        let one_div = coeff_replay_per_div + 2 * extraction_oneway;
        let pointadd = scaffold_after_div + 2 * one_div as isize;
        let gap = pointadd - 3_000_000isize;
        let extraction_oneway_budget = (((3_000_000isize - scaffold_after_div) / 2) as isize
            - coeff_replay_per_div as isize) / 2;
        let oneway_margin = extraction_oneway_budget - extraction_oneway as isize;
        println!("METRIC centered_restoring_payload_p99_bits={payload_p99}");
        println!("METRIC centered_restoring_count_p99={count_p99}");
        println!("METRIC centered_restoring_scratch_p99={scratch_p99}");
        println!("METRIC centered_restoring_extraction_oneway_ccx={extraction_oneway}");
        println!("METRIC centered_restoring_oneway_margin_ccx={oneway_margin}");
        println!("METRIC centered_restoring_barrel_gap_to_3m_ccx={gap}");
        eprintln!(
            "Centered restoring-sub/barrel ledger: payload_p99={payload_p99}, count_p99={count_p99}, scratch={scratch_p99}, extraction_oneway={extraction_oneway}, margin={oneway_margin}, pointadd={pointadd}, gap={gap}"
        );
        assert!(scratch_p99 > 663, "centered restoring quotient stream unexpectedly fits Google scratch");
        assert!(gap < 0, "restoring subtract + generic barrel no longer fits relaxed 3M");
    }

    #[test]
    fn centered_euclid_current_qbit_primitives_miss_relaxed_3m_budget() {
        // Correct the restoring-subtract opening against primitives we actually
        // have.  With a generic barrel, the centered extractor can afford only
        // about 2.5n CCX per quotient payload bit.  Separate compare+masked-sub
        // is ~5n, and trial subtract plus controlled add-back is still ~4n with
        // current quantum-controlled add primitives.  Therefore the route needs
        // a new fused borrow-exposing subtract; existing adders do not suffice.
        let payload_p99 = 337usize;
        let count_p99 = 119usize;
        let scaffold_after_div = 642_716isize;
        let per_qbit_replay_ccx = 587usize;
        let coeff_replay_per_div = payload_p99 * per_qbit_replay_ccx;
        let barrel_and_scan = count_p99 * (256usize * 8usize + 256usize);
        let extraction_oneway_budget = (((3_000_000isize - scaffold_after_div) / 2) as isize
            - coeff_replay_per_div as isize) / 2;
        let affordable_per_payload_bit = (extraction_oneway_budget - barrel_and_scan as isize) as f64
            / payload_p99 as f64;
        let gap_for = |per_payload_bit: usize| -> isize {
            let oneway = payload_p99 * per_payload_bit + barrel_and_scan;
            let one_div = coeff_replay_per_div + 2 * oneway;
            scaffold_after_div + 2 * one_div as isize - 3_000_000isize
        };
        let ideal_2n_gap = gap_for(2 * 256);
        let fused_25n_gap = gap_for((5 * 256) / 2);
        let compare_masked_3n_gap = gap_for(3 * 256);
        let restoring_current_4n_gap = gap_for(4 * 256);
        let compare_masked_current_5n_gap = gap_for(5 * 256);
        println!("METRIC centered_current_affordable_per_payload_bit_ccx={affordable_per_payload_bit:.3}");
        println!("METRIC centered_current_ideal_2n_gap_ccx={ideal_2n_gap}");
        println!("METRIC centered_current_fused_2p5n_gap_ccx={fused_25n_gap}");
        println!("METRIC centered_current_3n_gap_ccx={compare_masked_3n_gap}");
        println!("METRIC centered_current_4n_gap_ccx={restoring_current_4n_gap}");
        println!("METRIC centered_current_5n_gap_ccx={compare_masked_current_5n_gap}");
        eprintln!(
            "Centered current qbit primitive budget: affordable_per_bit={affordable_per_payload_bit:.1}, gaps 2n={ideal_2n_gap}, 2.5n={fused_25n_gap}, 3n={compare_masked_3n_gap}, 4n={restoring_current_4n_gap}, 5n={compare_masked_current_5n_gap}"
        );
        assert!(ideal_2n_gap < 0, "even ideal 2n restoring subtract misses; demote centered extractor");
        assert!(compare_masked_3n_gap > 0, "3n qbit primitive fits; existing compare/sub floor may suffice");
        assert!(restoring_current_4n_gap > 0 && compare_masked_current_5n_gap > 0, "current qbit primitives unexpectedly fit");
    }

    fn emit_masked_add_for_centered_restoring_test(
        b: &mut super::super::B,
        acc: &[super::super::QubitId],
        a: &[super::super::QubitId],
        ctrl: super::super::QubitId,
    ) {
        assert_eq!(acc.len(), a.len());
        let tmp = b.alloc_qubits(a.len());
        for i in 0..a.len() {
            b.ccx(ctrl, a[i], tmp[i]);
        }
        super::super::add_nbit_qq_fast(b, &tmp, acc);
        for i in (0..a.len()).rev() {
            b.ccx(ctrl, a[i], tmp[i]);
        }
        b.free_vec(&tmp);
    }

    fn emit_trial_restoring_subtract_for_centered_test(
        b: &mut super::super::B,
        u: &[super::super::QubitId],
        v: &[super::super::QubitId],
        q_success: super::super::QubitId,
    ) {
        assert_eq!(u.len(), v.len());
        let top_u = b.alloc_qubit();
        let top_v = b.alloc_qubit();
        let borrow = b.alloc_qubit();
        let mut u_ext = u.to_vec();
        u_ext.push(top_u);
        let mut v_ext = v.to_vec();
        v_ext.push(top_v);
        super::super::sub_nbit_qq_fast(b, &v_ext, &u_ext);
        b.cx(top_u, borrow);
        b.x(borrow);
        b.cx(borrow, q_success);
        b.x(borrow);
        emit_masked_add_for_centered_restoring_test(b, &u_ext, &v_ext, borrow);
        b.x(q_success);
        b.cx(q_success, borrow);
        b.x(q_success);
        b.free(borrow);
        b.free(top_v);
        b.free(top_u);
    }

    #[test]
    fn centered_restoring_subtract_current_circuit_confirms_over_budget() {
        // Concrete cost checkpoint for the q-bit primitive.  The obvious trial
        // subtract + masked add-back implementation uses only existing clean
        // adders, but its cost scales near 4n per quotient bit.  That confirms
        // the budget ledger above: current primitives miss relaxed 3M unless a
        // fused borrow-exposing subtract below ~2.5n exists.
        let cost_for = |n: usize| -> (usize, u32) {
            let mut b = super::super::B::new();
            let u = b.alloc_qubits(n);
            let v = b.alloc_qubits(n);
            let q = b.alloc_qubit();
            emit_trial_restoring_subtract_for_centered_test(&mut b, &u, &v, q);
            (local_count_ccx_for_plusminus_cost(&b.ops), b.peak_qubits)
        };
        let (ccx32, peak32) = cost_for(32);
        let (ccx64, peak64) = cost_for(64);
        let per_n64 = ccx64 as f64 / 64.0;

        let payload_p99 = 337usize;
        let count_p99 = 119usize;
        let scaffold_after_div = 642_716isize;
        let coeff_replay_per_div = payload_p99 * 587usize;
        let barrel_and_scan = count_p99 * (256usize * 8usize + 256usize);
        let per_payload_bit_256 = ((per_n64 * 256.0).ceil()) as usize;
        let oneway = payload_p99 * per_payload_bit_256 + barrel_and_scan;
        let one_div = coeff_replay_per_div + 2 * oneway;
        let gap = scaffold_after_div + 2 * one_div as isize - 3_000_000isize;
        println!("METRIC centered_restoring_circuit_ccx32={ccx32}");
        println!("METRIC centered_restoring_circuit_peak32={peak32}");
        println!("METRIC centered_restoring_circuit_ccx64={ccx64}");
        println!("METRIC centered_restoring_circuit_peak64={peak64}");
        println!("METRIC centered_restoring_circuit_per_n64={per_n64:.3}");
        println!("METRIC centered_restoring_circuit_gap_to_3m_ccx={gap}");
        eprintln!("Centered restoring subtract circuit: ccx32={ccx32}, peak32={peak32}, ccx64={ccx64}, peak64={peak64}, per_n64={per_n64:.2}, scaled_gap={gap}");
        assert!(per_n64 > 3.5, "current restoring subtract is near the fused target; revisit centered extractor");
        assert!(gap > 0, "current restoring subtract circuit fits relaxed 3M; prototype full extractor");
    }

    #[test]
    fn centered_euclid_nonrestoring_signed_digit_ledger_reopens_margin() {
        // New response to the fused-subtract blocker: do not restore the trial
        // subtract.  A non-restoring signed-remainder division step uses the
        // sign of the running remainder to choose add vs subtract of v<<k, so
        // each quotient digit can cost one controlled add/sub (~n) instead of a
        // compare plus conditional restore.  The quotient history becomes a
        // signed binary digit stream; replay can consume signed digits directly.
        // This is only a ledger until a toy reversible extractor validates the
        // signed-remainder invariant and final correction.
        let p = SECP256K1_P;
        let samples = 4096usize;
        let mut rng = 0x2800_c5d1_61d6_0001u64;
        let mut payload_bits = Vec::with_capacity(samples);
        let mut counts = Vec::with_capacity(samples);
        let mut max_qbits = 0usize;
        for _ in 0..samples {
            let mut x = rand_u256(&mut rng);
            if x.is_zero() { x = U256::from(1u64); }
            let qs = centered_euclid_abs_quotients_for_divisor(x, p);
            let payload = qs
                .iter()
                .map(|q| u512_bit_len_for_halfgcd_test(*q).max(1))
                .sum::<usize>();
            max_qbits = max_qbits.max(qs.iter().map(|q| u512_bit_len_for_halfgcd_test(*q).max(1)).max().unwrap_or(1));
            payload_bits.push(payload);
            counts.push(qs.len());
        }
        payload_bits.sort_unstable();
        counts.sort_unstable();
        let p99 = samples * 99 / 100;
        let payload_p99 = payload_bits[p99];
        let count_p99 = counts[p99];
        let scaffold_after_div = 642_716isize;
        let coeff_replay_per_digit = 587usize;
        let signed_digit_extract_per_digit = 256usize;
        let barrel_and_scan_per_quotient = 256usize * 8usize + 256usize;
        let coeff_replay_per_div = payload_p99 * coeff_replay_per_digit;
        let extraction_oneway = payload_p99 * signed_digit_extract_per_digit
            + count_p99 * barrel_and_scan_per_quotient;
        let one_div = coeff_replay_per_div + 2 * extraction_oneway;
        let pointadd = scaffold_after_div + 2 * one_div as isize;
        let gap = pointadd - 3_000_000isize;
        let extraction_oneway_budget = (((3_000_000isize - scaffold_after_div) / 2) as isize
            - coeff_replay_per_div as isize) / 2;
        let oneway_margin = extraction_oneway_budget - extraction_oneway as isize;
        println!("METRIC centered_nonrestoring_payload_p99_bits={payload_p99}");
        println!("METRIC centered_nonrestoring_count_p99={count_p99}");
        println!("METRIC centered_nonrestoring_max_qbits_sampled={max_qbits}");
        println!("METRIC centered_nonrestoring_extraction_oneway_ccx={extraction_oneway}");
        println!("METRIC centered_nonrestoring_oneway_margin_ccx={oneway_margin}");
        println!("METRIC centered_nonrestoring_gap_to_3m_ccx={gap}");
        eprintln!("Centered non-restoring signed-digit ledger: payload_p99={payload_p99}, count_p99={count_p99}, max_qbits={max_qbits}, extraction_oneway={extraction_oneway}, margin={oneway_margin}, pointadd={pointadd}, gap={gap}");
        assert!(gap < -300_000, "non-restoring signed digits do not leave enough margin to prototype");
    }

    #[test]
    fn centered_nonrestoring_final_nearest_correction_budget() {
        // The signed-digit non-restoring ledger still hid the conversion from
        // floor(|u|/|v|) to centered/nearest quotient.  Charge one correction
        // bit per quotient: compare 2r>v, conditionally subtract v from the
        // residual, and replay one extra signed digit.  This keeps the route
        // alive only if the correction overhead stays within the 3M margin.
        let p = SECP256K1_P;
        let samples = 4096usize;
        let mut rng = 0x2800_c5d1_c011_0001u64;
        let mut center_payload_bits = Vec::with_capacity(samples);
        let mut floor_payload_bits = Vec::with_capacity(samples);
        let mut counts = Vec::with_capacity(samples);
        let mut corrections = Vec::with_capacity(samples);
        for _ in 0..samples {
            let mut x = rand_u256(&mut rng);
            if x.is_zero() { x = U256::from(1u64); }
            let mut u = smag_for_halfgcd_test(false, u512_from_u256_for_halfgcd_test(p));
            let mut v = smag_for_halfgcd_test(false, u512_from_u256_for_halfgcd_test(x));
            let mut center_payload = 0usize;
            let mut floor_payload = 0usize;
            let mut count = 0usize;
            let mut correction_count = 0usize;
            while !v.mag.is_zero() {
                let q_floor = u.mag / v.mag;
                let r_floor = u.mag - q_floor * v.mag;
                let centered = (r_floor << 1usize) >= v.mag;
                let q = if centered { q_floor + U512::from(1u64) } else { q_floor };
                floor_payload += u512_bit_len_for_halfgcd_test(q_floor).max(1);
                center_payload += u512_bit_len_for_halfgcd_test(q).max(1);
                correction_count += centered as usize;
                count += 1;
                let q_neg = u.neg ^ v.neg;
                let qv = signed_mul_mag_for_halfgcd_test(v, q_neg, q);
                let r = signed_add_for_halfgcd_test(u, signed_neg_for_halfgcd_test(qv));
                u = v;
                v = r;
            }
            assert_eq!(u.mag, U512::from(1u64));
            center_payload_bits.push(center_payload);
            floor_payload_bits.push(floor_payload);
            counts.push(count);
            corrections.push(correction_count);
        }
        center_payload_bits.sort_unstable();
        floor_payload_bits.sort_unstable();
        counts.sort_unstable();
        corrections.sort_unstable();
        let p99 = samples * 99 / 100;
        let floor_payload_p99 = floor_payload_bits[p99];
        let center_payload_p99 = center_payload_bits[p99];
        let count_p99 = counts[p99];
        let corr_p99 = corrections[p99];
        let corr_max = *corrections.last().unwrap();
        let scaffold_after_div = 642_716isize;
        let replay_per_digit = 587usize;
        let n = 256usize;
        let barrel_and_scan_per_q = n * 8 + n;
        let floor_replay_per_div = (floor_payload_p99 + corr_p99) * replay_per_digit;
        let extraction_oneway = floor_payload_p99 * n
            + count_p99 * barrel_and_scan_per_q
            + count_p99 * 2 * n;
        let one_div = floor_replay_per_div + 2 * extraction_oneway;
        let pointadd = scaffold_after_div + 2 * one_div as isize;
        let gap = pointadd - 3_000_000isize;
        println!("METRIC centered_nonrestoring_floor_payload_p99_bits={floor_payload_p99}");
        println!("METRIC centered_nonrestoring_center_payload_p99_bits={center_payload_p99}");
        println!("METRIC centered_nonrestoring_correction_p99={corr_p99}");
        println!("METRIC centered_nonrestoring_correction_max={corr_max}");
        println!("METRIC centered_nonrestoring_corrected_extraction_oneway_ccx={extraction_oneway}");
        println!("METRIC centered_nonrestoring_corrected_gap_to_3m_ccx={gap}");
        eprintln!("Centered non-restoring nearest correction: floor_payload_p99={floor_payload_p99}, center_payload_p99={center_payload_p99}, count_p99={count_p99}, corr_p99={corr_p99}, corr_max={corr_max}, extraction_oneway={extraction_oneway}, gap={gap}");
        assert!(gap < 0, "nearest correction overhead kills non-restoring centered Euclid");
    }

    fn nonrestoring_floor_digits_for_centered_test(n: U512, d: U512) -> (usize, U512, bool) {
        assert!(!d.is_zero());
        if n.is_zero() { return (1, U512::ZERO, false); }
        let top = u512_bit_len_for_halfgcd_test(n).saturating_sub(u512_bit_len_for_halfgcd_test(d));
        let mut rem = smag_for_halfgcd_test(false, n);
        let mut q = smag_for_halfgcd_test(false, U512::ZERO);
        let mut digits = 0usize;
        for sh in (0..=top).rev() {
            let term = smag_for_halfgcd_test(false, d << sh);
            let qterm = smag_for_halfgcd_test(false, U512::from(1u64) << sh);
            if !rem.neg {
                rem = signed_add_for_halfgcd_test(rem, signed_neg_for_halfgcd_test(term));
                q = signed_add_for_halfgcd_test(q, qterm);
            } else {
                rem = signed_add_for_halfgcd_test(rem, term);
                q = signed_add_for_halfgcd_test(q, signed_neg_for_halfgcd_test(qterm));
            }
            digits += 1;
        }
        let mut final_negative = false;
        if rem.neg && !rem.mag.is_zero() {
            rem = signed_add_for_halfgcd_test(rem, smag_for_halfgcd_test(false, d));
            q = signed_add_for_halfgcd_test(q, smag_for_halfgcd_test(true, U512::from(1u64)));
            final_negative = true;
        }
        assert!(!rem.neg && rem.mag < d);
        assert!(!q.neg && q.mag == n / d, "non-restoring floor quotient mismatch");
        (digits, rem.mag, final_negative)
    }

    fn nonrestoring_floor_signed_digits_for_centered_test(n: U512, d: U512) -> Vec<(bool, usize)> {
        assert!(!d.is_zero());
        if n.is_zero() {
            return vec![(false, 0)];
        }
        let top = u512_bit_len_for_halfgcd_test(n).saturating_sub(u512_bit_len_for_halfgcd_test(d));
        let mut rem = smag_for_halfgcd_test(false, n);
        let mut q = smag_for_halfgcd_test(false, U512::ZERO);
        let mut digits = Vec::with_capacity(top + 2);
        for sh in (0..=top).rev() {
            let digit_neg = rem.neg;
            let term = smag_for_halfgcd_test(false, d << sh);
            let qterm = smag_for_halfgcd_test(false, U512::from(1u64) << sh);
            if digit_neg {
                rem = signed_add_for_halfgcd_test(rem, term);
                q = signed_add_for_halfgcd_test(q, signed_neg_for_halfgcd_test(qterm));
            } else {
                rem = signed_add_for_halfgcd_test(rem, signed_neg_for_halfgcd_test(term));
                q = signed_add_for_halfgcd_test(q, qterm);
            }
            digits.push((digit_neg, sh));
        }
        if rem.neg && !rem.mag.is_zero() {
            rem = signed_add_for_halfgcd_test(rem, smag_for_halfgcd_test(false, d));
            q = signed_add_for_halfgcd_test(q, smag_for_halfgcd_test(true, U512::from(1u64)));
            digits.push((true, 0));
        }
        assert!(!rem.neg && rem.mag < d);
        assert!(!q.neg && q.mag == n / d, "non-restoring signed digits mismatch");
        digits
    }

    fn nonrestoring_floor_restoring_final_digits_for_centered_test(
        n: U512,
        d: U512,
    ) -> Vec<(bool, usize)> {
        assert!(!d.is_zero());
        if n.is_zero() {
            return Vec::new();
        }
        let top = u512_bit_len_for_halfgcd_test(n).saturating_sub(u512_bit_len_for_halfgcd_test(d));
        let mut rem = smag_for_halfgcd_test(false, n);
        let mut q = smag_for_halfgcd_test(false, U512::ZERO);
        let mut digits = Vec::with_capacity(top + 1);
        for sh in (1..=top).rev() {
            let digit_neg = rem.neg;
            let term = smag_for_halfgcd_test(false, d << sh);
            let qterm = smag_for_halfgcd_test(false, U512::from(1u64) << sh);
            if digit_neg {
                rem = signed_add_for_halfgcd_test(rem, term);
                q = signed_add_for_halfgcd_test(q, signed_neg_for_halfgcd_test(qterm));
            } else {
                rem = signed_add_for_halfgcd_test(rem, signed_neg_for_halfgcd_test(term));
                q = signed_add_for_halfgcd_test(q, qterm);
            }
            digits.push((digit_neg, sh));
        }
        if rem.neg && rem.mag > d {
            rem = signed_add_for_halfgcd_test(rem, smag_for_halfgcd_test(false, d << 1usize));
            q = signed_add_for_halfgcd_test(q, smag_for_halfgcd_test(true, U512::from(2u64)));
            digits.push((true, 1));
        } else if rem.neg && !rem.mag.is_zero() {
            rem = signed_add_for_halfgcd_test(rem, smag_for_halfgcd_test(false, d));
            q = signed_add_for_halfgcd_test(q, smag_for_halfgcd_test(true, U512::from(1u64)));
            digits.push((true, 0));
        } else if !rem.neg && rem.mag >= d {
            rem = signed_add_for_halfgcd_test(rem, signed_neg_for_halfgcd_test(smag_for_halfgcd_test(false, d)));
            q = signed_add_for_halfgcd_test(q, smag_for_halfgcd_test(false, U512::from(1u64)));
            digits.push((false, 0));
        }
        assert!(
            !rem.neg && rem.mag < d,
            "restoring-final remainder escaped floor range n={n} d={d} top={top} rem={rem:?} q={q:?}"
        );
        assert!(
            !q.neg && q.mag == n / d,
            "restoring-final signed digits did not produce floor quotient"
        );
        digits
    }

    fn nonrestoring_prefinal_signed_digits_for_centered_test(
        n: U512,
        d: U512,
    ) -> (Vec<(bool, usize)>, SignedMagU512ForHalfGcdTest, U512) {
        assert!(!d.is_zero());
        assert!(!n.is_zero());
        let top = u512_bit_len_for_halfgcd_test(n).saturating_sub(u512_bit_len_for_halfgcd_test(d));
        let mut rem = smag_for_halfgcd_test(false, n);
        let mut q = smag_for_halfgcd_test(false, U512::ZERO);
        let mut digits = Vec::with_capacity(top + 1);
        for sh in (0..=top).rev() {
            let digit_neg = rem.neg;
            let term = smag_for_halfgcd_test(false, d << sh);
            let qterm = smag_for_halfgcd_test(false, U512::from(1u64) << sh);
            if digit_neg {
                rem = signed_add_for_halfgcd_test(rem, term);
                q = signed_add_for_halfgcd_test(q, signed_neg_for_halfgcd_test(qterm));
            } else {
                rem = signed_add_for_halfgcd_test(rem, signed_neg_for_halfgcd_test(term));
                q = signed_add_for_halfgcd_test(q, qterm);
            }
            digits.push((digit_neg, sh));
        }
        assert!(!q.neg, "prefinal non-restoring quotient went negative");
        assert!(
            rem.mag < (d << 1usize),
            "prefinal non-restoring remainder escaped two-divisor bound"
        );
        (digits, rem, q.mag)
    }

    fn low_u256_from_u512_for_centered_test(x: U512) -> U256 {
        let limbs = x.as_limbs();
        U256::from_limbs([limbs[0], limbs[1], limbs[2], limbs[3]])
    }

    fn signed_u512_mod_u256_for_centered_test(
        x: SignedMagU512ForHalfGcdTest,
        p: U256,
    ) -> U256 {
        let p512 = u512_from_u256_for_halfgcd_test(p);
        let rem = x.mag % p512;
        if rem.is_zero() {
            U256::ZERO
        } else if x.neg {
            p - low_u256_from_u512_for_centered_test(rem)
        } else {
            low_u256_from_u512_for_centered_test(rem)
        }
    }

    fn direct_centered_public_width_bound_for_step(n: usize, step: usize) -> usize {
        n.saturating_sub(step / 2).max(1)
    }

    #[test]
    fn centered_nonrestoring_full_corrections_kill_relaxed_margin() {
        // Guardrail after the optimistic signed-digit ledger: full non-restoring
        // floor division needs a final negative-remainder correction, and
        // centered quotients need the nearest correction.  Charging both erases
        // the relaxed 3M margin.
        let p = SECP256K1_P;
        let samples = 4096usize;
        let mut rng = 0x2800_c5d1_f100_0001u64;
        let mut floor_payloads = Vec::with_capacity(samples);
        let mut center_payloads = Vec::with_capacity(samples);
        let mut counts = Vec::with_capacity(samples);
        let mut final_negs = Vec::with_capacity(samples);
        let mut nearests = Vec::with_capacity(samples);
        for _ in 0..samples {
            let mut x = rand_u256(&mut rng);
            if x.is_zero() { x = U256::from(1u64); }
            let mut u = smag_for_halfgcd_test(false, u512_from_u256_for_halfgcd_test(p));
            let mut v = smag_for_halfgcd_test(false, u512_from_u256_for_halfgcd_test(x));
            let (mut floor_payload, mut center_payload, mut count, mut final_count, mut near_count) = (0usize, 0usize, 0usize, 0usize, 0usize);
            while !v.mag.is_zero() {
                let (digits, floor_rem, final_negative) = nonrestoring_floor_digits_for_centered_test(u.mag, v.mag);
                let q_floor = u.mag / v.mag;
                let nearest = (floor_rem << 1usize) >= v.mag;
                let q = if nearest { q_floor + U512::from(1u64) } else { q_floor };
                floor_payload += digits;
                center_payload += u512_bit_len_for_halfgcd_test(q).max(1);
                final_count += final_negative as usize;
                near_count += nearest as usize;
                count += 1;
                let q_neg = u.neg ^ v.neg;
                let qv = signed_mul_mag_for_halfgcd_test(v, q_neg, q);
                let r = signed_add_for_halfgcd_test(u, signed_neg_for_halfgcd_test(qv));
                u = v;
                v = r;
            }
            assert_eq!(u.mag, U512::from(1u64));
            floor_payloads.push(floor_payload);
            center_payloads.push(center_payload);
            counts.push(count);
            final_negs.push(final_count);
            nearests.push(near_count);
        }
        floor_payloads.sort_unstable();
        center_payloads.sort_unstable();
        counts.sort_unstable();
        final_negs.sort_unstable();
        nearests.sort_unstable();
        let p99 = samples * 99 / 100;
        let floor_payload_p99 = floor_payloads[p99];
        let center_payload_p99 = center_payloads[p99];
        let count_p99 = counts[p99];
        let final_p99 = final_negs[p99];
        let nearest_p99 = nearests[p99];
        let total_corr_p99 = final_p99 + nearest_p99;
        let n = 256usize;
        let replay_per_div = (floor_payload_p99 + total_corr_p99) * 587usize;
        let extraction_oneway = floor_payload_p99 * n + count_p99 * (n * 8 + n) + count_p99 * 3 * n;
        let pointadd = 642_716isize + 2 * (replay_per_div + 2 * extraction_oneway) as isize;
        let gap = pointadd - 3_000_000isize;
        println!("METRIC centered_nonrest_floor_digit_payload_p99={floor_payload_p99}");
        println!("METRIC centered_nonrest_center_binary_payload_p99={center_payload_p99}");
        println!("METRIC centered_nonrest_count_p99={count_p99}");
        println!("METRIC centered_nonrest_final_negative_p99={final_p99}");
        println!("METRIC centered_nonrest_nearest_correction_p99={nearest_p99}");
        println!("METRIC centered_nonrest_total_corrections_p99={total_corr_p99}");
        println!("METRIC centered_nonrest_fullcorr_extraction_oneway_ccx={extraction_oneway}");
        println!("METRIC centered_nonrest_fullcorr_gap_to_3m_ccx={gap}");
        eprintln!("Centered non-restoring full corrections kill: floor_payload_p99={floor_payload_p99}, center_payload_p99={center_payload_p99}, count_p99={count_p99}, final_p99={final_p99}, nearest_p99={nearest_p99}, extraction={extraction_oneway}, gap={gap}");
        assert!(gap > 0, "full corrections still fit; build non-restoring extractor circuit");
    }

    #[test]
    fn direct_centered_nonrestoring_rounding_numerator_reopens_relaxed_margin() {
        // Repair attempt for the killed non-restoring ledger above: compute the
        // centered quotient directly as floor((|u| + |v|/2) / |v|).  This
        // removes the separate nearest-quotient compare/correction channel.
        // The remaining correction is only the standard non-restoring final
        // negative-remainder fix, whose control is the final remainder sign.
        let p = SECP256K1_P;
        let samples = 4096usize;
        let mut rng = 0x2800_c5d1_d1ce_0001u64;
        let mut digit_payloads = Vec::with_capacity(samples);
        let mut centered_payloads = Vec::with_capacity(samples);
        let mut counts = Vec::with_capacity(samples);
        let mut final_negs = Vec::with_capacity(samples);
        for _ in 0..samples {
            let mut x = rand_u256(&mut rng);
            if x.is_zero() { x = U256::from(1u64); }
            let mut u = smag_for_halfgcd_test(false, u512_from_u256_for_halfgcd_test(p));
            let mut v = smag_for_halfgcd_test(false, u512_from_u256_for_halfgcd_test(x));
            let (mut digit_payload, mut centered_payload, mut count, mut final_count) = (0usize, 0usize, 0usize, 0usize);
            while !v.mag.is_zero() {
                let q_floor = u.mag / v.mag;
                let r_floor = u.mag - q_floor * v.mag;
                let q_center = if (r_floor << 1usize) >= v.mag {
                    q_floor + U512::from(1u64)
                } else {
                    q_floor
                };
                let adjusted = u.mag + (v.mag >> 1usize);
                let q_direct = adjusted / v.mag;
                assert_eq!(q_direct, q_center, "rounding numerator did not match centered quotient");
                let (digits, _rem, final_negative) = nonrestoring_floor_digits_for_centered_test(adjusted, v.mag);
                digit_payload += digits;
                centered_payload += u512_bit_len_for_halfgcd_test(q_direct).max(1);
                final_count += final_negative as usize;
                count += 1;
                let q_neg = u.neg ^ v.neg;
                let qv = signed_mul_mag_for_halfgcd_test(v, q_neg, q_direct);
                let r = signed_add_for_halfgcd_test(u, signed_neg_for_halfgcd_test(qv));
                u = v;
                v = r;
            }
            assert_eq!(u.mag, U512::from(1u64));
            digit_payloads.push(digit_payload);
            centered_payloads.push(centered_payload);
            counts.push(count);
            final_negs.push(final_count);
        }
        digit_payloads.sort_unstable();
        centered_payloads.sort_unstable();
        counts.sort_unstable();
        final_negs.sort_unstable();
        let p99 = samples * 99 / 100;
        let digit_payload_p99 = digit_payloads[p99];
        let centered_payload_p99 = centered_payloads[p99];
        let count_p99 = counts[p99];
        let final_p99 = final_negs[p99];
        let final_max = *final_negs.last().unwrap();
        let n = 256usize;
        let replay_per_div = (digit_payload_p99 + final_p99) * 587usize;
        let barrel_and_scan = count_p99 * (n * 8 + n);
        let final_fix = count_p99 * n;
        let extraction_oneway = digit_payload_p99 * n + barrel_and_scan + final_fix;
        let pointadd = 642_716isize + 2 * (replay_per_div + 2 * extraction_oneway) as isize;
        let gap = pointadd - 3_000_000isize;
        println!("METRIC centered_direct_round_digit_payload_p99={digit_payload_p99}");
        println!("METRIC centered_direct_round_binary_payload_p99={centered_payload_p99}");
        println!("METRIC centered_direct_round_count_p99={count_p99}");
        println!("METRIC centered_direct_round_final_negative_p99={final_p99}");
        println!("METRIC centered_direct_round_final_negative_max={final_max}");
        println!("METRIC centered_direct_round_extraction_oneway_ccx={extraction_oneway}");
        println!("METRIC centered_direct_round_gap_to_3m_ccx={gap}");
        eprintln!("Centered direct-rounding non-restoring ledger: digit_payload_p99={digit_payload_p99}, centered_payload_p99={centered_payload_p99}, count_p99={count_p99}, final_p99={final_p99}, extraction={extraction_oneway}, gap={gap}");
        assert!(gap < 0, "direct-centered non-restoring margin disappeared; keep route demoted");
    }

    fn emit_sign_controlled_addsub_digit_for_centered_test(
        b: &mut super::super::B,
        rem: &[super::super::QubitId],
        shifted_v: &[super::super::QubitId],
        sign_hist: super::super::QubitId,
    ) {
        assert_eq!(rem.len(), shifted_v.len());
        let nonnegative = b.alloc_qubit();
        b.x(nonnegative);
        b.cx(sign_hist, nonnegative);
        super::super::cucc_sub_ctrl(b, shifted_v, rem, nonnegative);
        super::super::cucc_add_ctrl(b, shifted_v, rem, sign_hist);
        b.cx(sign_hist, nonnegative);
        b.x(nonnegative);
        b.free(nonnegative);
    }

    fn emit_active_sign_controlled_addsub_digit_for_centered_test(
        b: &mut super::super::B,
        acc: &[super::super::QubitId],
        shifted_v: &[super::super::QubitId],
        active: super::super::QubitId,
        sign_hist: super::super::QubitId,
    ) {
        assert_eq!(acc.len(), shifted_v.len());
        let nonnegative = b.alloc_qubit();
        let do_sub = b.alloc_qubit();
        let do_add = b.alloc_qubit();
        b.x(nonnegative);
        b.cx(sign_hist, nonnegative);
        b.ccx(active, nonnegative, do_sub);
        b.ccx(active, sign_hist, do_add);
        super::super::cucc_sub_ctrl(b, shifted_v, acc, do_sub);
        super::super::cucc_add_ctrl(b, shifted_v, acc, do_add);
        b.ccx(active, sign_hist, do_add);
        b.ccx(active, nonnegative, do_sub);
        b.cx(sign_hist, nonnegative);
        b.x(nonnegative);
        b.free(do_add);
        b.free(do_sub);
        b.free(nonnegative);
    }

    fn emit_controlled_integer_add_coherent_for_centered_test(
        b: &mut super::super::B,
        acc: &[super::super::QubitId],
        a: &[super::super::QubitId],
        ctrl: super::super::QubitId,
        subtract: bool,
    ) {
        assert_eq!(acc.len(), a.len());
        let f = b.alloc_qubits(acc.len());
        for i in 0..acc.len() {
            b.ccx(ctrl, a[i], f[i]);
        }
        if subtract {
            super::super::sub_nbit_qq(b, &f, acc);
        } else {
            super::super::add_nbit_qq(b, &f, acc);
        }
        for i in (0..acc.len()).rev() {
            b.ccx(ctrl, a[i], f[i]);
        }
        b.free_vec(&f);
    }

    fn controlled_integer_add_coherent_cost_for_centered_test(width: usize) -> usize {
        let mut b = super::super::B::new();
        let acc = b.alloc_qubits(width);
        let a = b.alloc_qubits(width);
        let ctrl = b.alloc_qubit();
        let start = b.ops.len();
        emit_controlled_integer_add_coherent_for_centered_test(&mut b, &acc, &a, ctrl, false);
        local_count_ccx_for_plusminus_cost(&b.ops[start..])
    }

    fn emit_fused_sign_controlled_addsub_digit_for_centered_test(
        b: &mut super::super::B,
        rem: &[super::super::QubitId],
        shifted_v: &[super::super::QubitId],
        sign_hist: super::super::QubitId,
    ) {
        assert_eq!(rem.len(), shifted_v.len());
        let nonnegative = b.alloc_qubit();
        b.x(nonnegative);
        b.cx(sign_hist, nonnegative);
        for &q in shifted_v {
            b.cx(nonnegative, q);
        }
        super::super::cuccaro_add_fast(b, shifted_v, rem, nonnegative);
        for &q in shifted_v.iter().rev() {
            b.cx(nonnegative, q);
        }
        b.cx(sign_hist, nonnegative);
        b.x(nonnegative);
        b.free(nonnegative);
    }

    fn emit_active_fused_sign_controlled_addsub_digit_for_centered_test(
        b: &mut super::super::B,
        acc: &[super::super::QubitId],
        shifted_v: &[super::super::QubitId],
        active: super::super::QubitId,
        sign_hist: super::super::QubitId,
    ) {
        assert_eq!(acc.len(), shifted_v.len());
        let gated = b.alloc_qubits(shifted_v.len());
        for i in 0..shifted_v.len() {
            b.ccx(active, shifted_v[i], gated[i]);
        }
        emit_fused_sign_controlled_addsub_digit_for_centered_test(
            b,
            acc,
            &gated,
            sign_hist,
        );
        for i in (0..shifted_v.len()).rev() {
            b.ccx(active, shifted_v[i], gated[i]);
        }
        b.free_vec(&gated);
    }

    fn emit_fused_sign_controlled_addsub_digit_opposite_for_centered_test(
        b: &mut super::super::B,
        acc: &[super::super::QubitId],
        shifted_v: &[super::super::QubitId],
        sign_hist: super::super::QubitId,
    ) {
        b.x(sign_hist);
        emit_fused_sign_controlled_addsub_digit_for_centered_test(b, acc, shifted_v, sign_hist);
        b.x(sign_hist);
    }

    fn emit_shift_right_1_nooverflow_for_centered_test(
        b: &mut super::super::B,
        v: &[super::super::QubitId],
    ) {
        for i in 0..v.len() - 1 {
            b.swap(v[i], v[i + 1]);
        }
    }

    fn emit_arithmetic_shift_right_1_exact_for_centered_test(
        b: &mut super::super::B,
        v: &[super::super::QubitId],
    ) {
        assert!(v.len() >= 2);
        emit_shift_right_1_nooverflow_for_centered_test(b, v);
        b.cx(v[v.len() - 2], v[v.len() - 1]);
    }

    fn emit_shift_right_1_nooverflow_inverse_for_centered_test(
        b: &mut super::super::B,
        v: &[super::super::QubitId],
    ) {
        for i in (0..v.len() - 1).rev() {
            b.swap(v[i], v[i + 1]);
        }
    }

    fn emit_arithmetic_shift_right_1_exact_inverse_for_centered_test(
        b: &mut super::super::B,
        v: &[super::super::QubitId],
    ) {
        assert!(v.len() >= 2);
        b.cx(v[v.len() - 2], v[v.len() - 1]);
        emit_shift_right_1_nooverflow_inverse_for_centered_test(b, v);
    }

    fn emit_controlled_shift_left_1_with_spill_for_centered_test(
        b: &mut super::super::B,
        v: &[super::super::QubitId],
        ctrl: super::super::QubitId,
        spill: super::super::QubitId,
    ) {
        assert!(!v.is_empty());
        for i in (0..v.len()).rev() {
            let hi = if i + 1 == v.len() { spill } else { v[i + 1] };
            super::super::cswap(b, ctrl, v[i], hi);
        }
    }

    fn emit_controlled_shift_left_1_with_spill_inverse_for_centered_test(
        b: &mut super::super::B,
        v: &[super::super::QubitId],
        ctrl: super::super::QubitId,
        spill: super::super::QubitId,
    ) {
        assert!(!v.is_empty());
        for i in 0..v.len() {
            let hi = if i + 1 == v.len() { spill } else { v[i + 1] };
            super::super::cswap(b, ctrl, v[i], hi);
        }
    }

    fn emit_bitctrl_barrel_left_shift_unsigned_exact_for_centered_test(
        b: &mut super::super::B,
        v: &[super::super::QubitId],
        kbits: &[super::super::BitId],
        spill: &[super::super::QubitId],
    ) {
        assert!(spill.len() >= v.len());
        for (j, &ctrl) in kbits.iter().enumerate() {
            let s = 1usize << j;
            if s >= v.len() { break; }
            for i in (0..v.len()).rev() {
                let lo = if i < s { spill[i] } else { v[i - s] };
                b.swap_if(lo, v[i], ctrl);
            }
        }
    }

    fn emit_toy_direct_centered_nonrestoring_extractor_for_centered_test(
        b: &mut super::super::B,
        rem: &[super::super::QubitId],
        divisor: &[super::super::QubitId],
        digit_hist: &[super::super::QubitId],
        final_negative: super::super::QubitId,
    ) {
        assert_eq!(digit_hist.len(), 6);
        assert_eq!(rem.len(), 11);
        assert_eq!(divisor.len(), 4);
        let shifted_v = b.alloc_qubits(rem.len());
        for i in 0..divisor.len() {
            b.cx(divisor[i], shifted_v[i + 5]);
        }
        for sh in (0..digit_hist.len()).rev() {
            b.cx(rem[rem.len() - 1], digit_hist[sh]);
            emit_fused_sign_controlled_addsub_digit_for_centered_test(b, rem, &shifted_v, digit_hist[sh]);
            if sh != 0 {
                emit_shift_right_1_nooverflow_for_centered_test(b, &shifted_v);
            }
        }
        b.cx(rem[rem.len() - 1], final_negative);
        emit_controlled_integer_add_for_plusminus(b, rem, &shifted_v, final_negative, false);
        for i in (0..divisor.len()).rev() {
            b.cx(divisor[i], shifted_v[i]);
        }
        b.free_vec(&shifted_v);
    }

    fn emit_toy_direct_centered_nonrestoring_inline_coeff_for_centered_test(
        b: &mut super::super::B,
        rem: &[super::super::QubitId],
        divisor: &[super::super::QubitId],
        coeff_acc: &[super::super::QubitId],
        coeff_v: &[super::super::QubitId],
        digit_hist: &[super::super::QubitId],
        final_negative: super::super::QubitId,
        q_neg: bool,
        apply_final_coeff_correction: bool,
        coeff_final_before_rem: bool,
        final_coeff_from_coeff_v: bool,
        final_coeff_coherent: bool,
        centered_remainder: bool,
    ) {
        assert_eq!(digit_hist.len(), 6);
        assert_eq!(rem.len(), 11);
        assert_eq!(divisor.len(), 4);
        assert_eq!(coeff_acc.len(), coeff_v.len());
        let top_shift = digit_hist.len() - 1;
        assert!(coeff_v.len() > top_shift);
        let shifted_v = b.alloc_qubits(rem.len());
        let shifted_cv = b.alloc_qubits(coeff_v.len());
        for i in 0..divisor.len() {
            b.cx(divisor[i], shifted_v[i + top_shift]);
        }
        for i in 0..coeff_v.len() - top_shift {
            b.cx(coeff_v[i], shifted_cv[i + top_shift]);
        }
        for sh in (0..digit_hist.len()).rev() {
            b.cx(rem[rem.len() - 1], digit_hist[sh]);
            emit_fused_sign_controlled_addsub_digit_for_centered_test(
                b,
                rem,
                &shifted_v,
                digit_hist[sh],
            );
            if q_neg {
                b.x(digit_hist[sh]);
            }
            emit_fused_sign_controlled_addsub_digit_for_centered_test(
                b,
                coeff_acc,
                &shifted_cv,
                digit_hist[sh],
            );
            if q_neg {
                b.x(digit_hist[sh]);
            }
            if sh != 0 {
                emit_shift_right_1_nooverflow_for_centered_test(b, &shifted_v);
                emit_arithmetic_shift_right_1_exact_for_centered_test(b, &shifted_cv);
            }
        }
        b.cx(rem[rem.len() - 1], final_negative);
        let mut shifted_cv_uncopied = false;
        if apply_final_coeff_correction && coeff_final_before_rem {
            if final_coeff_from_coeff_v {
                for i in (0..coeff_v.len()).rev() {
                    b.cx(coeff_v[i], shifted_cv[i]);
                }
                shifted_cv_uncopied = true;
                if final_coeff_coherent {
                    emit_controlled_integer_add_coherent_for_centered_test(
                        b,
                        coeff_acc,
                        coeff_v,
                        final_negative,
                        q_neg,
                    );
                } else {
                    emit_controlled_integer_add_for_plusminus(
                        b,
                        coeff_acc,
                        coeff_v,
                        final_negative,
                        q_neg,
                    );
                }
            } else {
                if final_coeff_coherent {
                    emit_controlled_integer_add_coherent_for_centered_test(
                        b,
                        coeff_acc,
                        &shifted_cv,
                        final_negative,
                        q_neg,
                    );
                } else {
                    emit_controlled_integer_add_for_plusminus(
                        b,
                        coeff_acc,
                        &shifted_cv,
                        final_negative,
                        q_neg,
                    );
                }
            }
        }
        if centered_remainder {
            let half_v = b.alloc_qubits(rem.len());
            for i in 1..divisor.len() {
                b.cx(divisor[i], half_v[i - 1]);
            }
            emit_centered_final_half_fix_for_centered_test(
                b,
                rem,
                &half_v,
                divisor[0],
                final_negative,
            );
            for i in (1..divisor.len()).rev() {
                b.cx(divisor[i], half_v[i - 1]);
            }
            b.free_vec(&half_v);
        } else {
            emit_controlled_integer_add_for_plusminus(b, rem, &shifted_v, final_negative, false);
        }
        if apply_final_coeff_correction && !coeff_final_before_rem {
            if final_coeff_from_coeff_v {
                for i in (0..coeff_v.len()).rev() {
                    b.cx(coeff_v[i], shifted_cv[i]);
                }
                shifted_cv_uncopied = true;
                if final_coeff_coherent {
                    emit_controlled_integer_add_coherent_for_centered_test(
                        b,
                        coeff_acc,
                        coeff_v,
                        final_negative,
                        q_neg,
                    );
                } else {
                    emit_controlled_integer_add_for_plusminus(
                        b,
                        coeff_acc,
                        coeff_v,
                        final_negative,
                        q_neg,
                    );
                }
            } else {
                if final_coeff_coherent {
                    emit_controlled_integer_add_coherent_for_centered_test(
                        b,
                        coeff_acc,
                        &shifted_cv,
                        final_negative,
                        q_neg,
                    );
                } else {
                    emit_controlled_integer_add_for_plusminus(
                        b,
                        coeff_acc,
                        &shifted_cv,
                        final_negative,
                        q_neg,
                    );
                }
            }
        }
        if !shifted_cv_uncopied {
            for i in (0..coeff_v.len()).rev() {
                b.cx(coeff_v[i], shifted_cv[i]);
            }
        }
        for i in (0..divisor.len()).rev() {
            b.cx(divisor[i], shifted_v[i]);
        }
        b.free_vec(&shifted_cv);
        b.free_vec(&shifted_v);
    }

    fn emit_toy_halfgcd_active_floor_inline_coeff_for_centered_test(
        b: &mut super::super::B,
        rem: &[super::super::QubitId],
        divisor: &[super::super::QubitId],
        coeff_acc: &[super::super::QubitId],
        coeff_v: &[super::super::QubitId],
        digit_hist: &[super::super::QubitId],
        final_negative: super::super::QubitId,
        active: super::super::QubitId,
    ) {
        assert_eq!(digit_hist.len(), 6);
        assert_eq!(rem.len(), 11);
        assert_eq!(divisor.len(), 4);
        assert_eq!(coeff_acc.len(), coeff_v.len());
        let top_shift = digit_hist.len() - 1;
        assert!(coeff_v.len() > top_shift);
        let shifted_v = b.alloc_qubits(rem.len());
        let shifted_cv = b.alloc_qubits(coeff_v.len());
        for i in 0..divisor.len() {
            b.cx(divisor[i], shifted_v[i + top_shift]);
        }
        for i in 0..coeff_v.len() - top_shift {
            b.cx(coeff_v[i], shifted_cv[i + top_shift]);
        }
        for sh in (0..digit_hist.len()).rev() {
            b.ccx(active, rem[rem.len() - 1], digit_hist[sh]);
            emit_active_sign_controlled_addsub_digit_for_centered_test(
                b,
                rem,
                &shifted_v,
                active,
                digit_hist[sh],
            );
            emit_active_sign_controlled_addsub_digit_for_centered_test(
                b,
                coeff_acc,
                &shifted_cv,
                active,
                digit_hist[sh],
            );
            if sh != 0 {
                emit_shift_right_1_nooverflow_for_centered_test(b, &shifted_v);
                emit_arithmetic_shift_right_1_exact_for_centered_test(b, &shifted_cv);
            }
        }
        b.ccx(active, rem[rem.len() - 1], final_negative);
        emit_controlled_integer_add_coherent_for_centered_test(
            b,
            rem,
            &shifted_v,
            final_negative,
            false,
        );
        emit_controlled_integer_add_coherent_for_centered_test(
            b,
            coeff_acc,
            &shifted_cv,
            final_negative,
            false,
        );
        for i in (0..coeff_v.len()).rev() {
            b.cx(coeff_v[i], shifted_cv[i]);
        }
        for i in (0..divisor.len()).rev() {
            b.cx(divisor[i], shifted_v[i]);
        }
        b.free_vec(&shifted_cv);
        b.free_vec(&shifted_v);
    }

    fn emit_toy_halfgcd_fixed_bound_active_prefix_for_centered_test(
        b: &mut super::super::B,
        u: &[super::super::QubitId],
        v: &[super::super::QubitId],
        coeff_b: &[super::super::QubitId],
        coeff_d: &[super::super::QubitId],
        digit_hist: &[Vec<super::super::QubitId>],
        final_negative: &[super::super::QubitId],
        active_hist: &[super::super::QubitId],
    ) {
        assert_eq!(digit_hist.len(), final_negative.len());
        assert_eq!(digit_hist.len(), active_hist.len());
        for step in 0..active_hist.len() {
            super::super::cmp_eq_zero_into(b, v, active_hist[step]);
            b.x(active_hist[step]);
            emit_toy_halfgcd_active_floor_inline_coeff_for_centered_test(
                b,
                u,
                v,
                coeff_b,
                coeff_d,
                &digit_hist[step],
                final_negative[step],
                active_hist[step],
            );
            emit_toy_halfgcd_conditional_second_column_swap_for_centered_test(
                b,
                u,
                v,
                coeff_b,
                coeff_d,
                active_hist[step],
            );
        }
    }

    fn emit_toy_halfgcd_floor_inline_coeff_inverse_for_centered_test(
        b: &mut super::super::B,
        rem: &[super::super::QubitId],
        divisor: &[super::super::QubitId],
        coeff_acc: &[super::super::QubitId],
        coeff_v: &[super::super::QubitId],
        digit_hist: &[super::super::QubitId],
        final_negative: super::super::QubitId,
    ) {
        assert_eq!(digit_hist.len(), 6);
        assert_eq!(rem.len(), 11);
        assert_eq!(divisor.len(), 4);
        assert_eq!(coeff_acc.len(), coeff_v.len());
        let top_shift = digit_hist.len() - 1;
        let shifted_v = b.alloc_qubits(rem.len());
        let shifted_cv = b.alloc_qubits(coeff_v.len());
        for i in 0..divisor.len() {
            b.cx(divisor[i], shifted_v[i]);
        }
        for i in 0..coeff_v.len() {
            b.cx(coeff_v[i], shifted_cv[i]);
        }

        emit_controlled_integer_add_for_plusminus(
            b,
            coeff_acc,
            &shifted_cv,
            final_negative,
            true,
        );
        emit_controlled_integer_add_for_plusminus(
            b,
            rem,
            &shifted_v,
            final_negative,
            true,
        );
        b.cx(rem[rem.len() - 1], final_negative);

        for sh in 0..digit_hist.len() {
            emit_fused_sign_controlled_addsub_digit_opposite_for_centered_test(
                b,
                coeff_acc,
                &shifted_cv,
                digit_hist[sh],
            );
            emit_fused_sign_controlled_addsub_digit_opposite_for_centered_test(
                b,
                rem,
                &shifted_v,
                digit_hist[sh],
            );
            b.cx(rem[rem.len() - 1], digit_hist[sh]);
            if sh != top_shift {
                emit_shift_right_1_nooverflow_inverse_for_centered_test(b, &shifted_v);
                emit_arithmetic_shift_right_1_exact_inverse_for_centered_test(
                    b,
                    &shifted_cv,
                );
            }
        }

        for i in (0..coeff_v.len() - top_shift).rev() {
            b.cx(coeff_v[i], shifted_cv[i + top_shift]);
        }
        for i in (0..divisor.len()).rev() {
            b.cx(divisor[i], shifted_v[i + top_shift]);
        }
        b.free_vec(&shifted_cv);
        b.free_vec(&shifted_v);
    }

    fn emit_toy_halfgcd_conditional_second_column_swap_for_centered_test(
        b: &mut super::super::B,
        u: &[super::super::QubitId],
        v: &[super::super::QubitId],
        coeff_b: &[super::super::QubitId],
        coeff_d: &[super::super::QubitId],
        active: super::super::QubitId,
    ) {
        assert!(u.len() >= v.len());
        assert_eq!(coeff_b.len(), coeff_d.len());
        for i in 0..v.len() {
            super::super::cswap(b, active, u[i], v[i]);
        }
        for i in 0..coeff_b.len() {
            super::super::cswap(b, active, coeff_b[i], coeff_d[i]);
        }
    }

    fn emit_toy_direct_centered_nonrestoring_inline_coeff_restoring_final_for_centered_test(
        b: &mut super::super::B,
        rem: &[super::super::QubitId],
        divisor: &[super::super::QubitId],
        coeff_acc: &[super::super::QubitId],
        coeff_v: &[super::super::QubitId],
        digit_hist: &[super::super::QubitId],
        final_neg1: super::super::QubitId,
        final_neg2: super::super::QubitId,
        final_pos_ge: super::super::QubitId,
        final_lt_tmp: super::super::QubitId,
        q_neg: bool,
    ) {
        assert_eq!(digit_hist.len(), 6);
        assert_eq!(rem.len(), 11);
        assert_eq!(divisor.len(), 4);
        assert_eq!(coeff_acc.len(), coeff_v.len());
        let top_shift = digit_hist.len() - 1;
        assert!(coeff_v.len() > top_shift);
        let sign_false = b.alloc_qubit();
        let sign_true = b.alloc_qubit();
        b.x(sign_true);
        let coeff_sign_pos = if q_neg { sign_true } else { sign_false };
        let coeff_sign_neg = if q_neg { sign_false } else { sign_true };

        let shifted_v = b.alloc_qubits(rem.len());
        let shifted_cv = b.alloc_qubits(coeff_v.len());
        for i in 0..divisor.len() {
            b.cx(divisor[i], shifted_v[i + top_shift]);
        }
        for i in 0..coeff_v.len() - top_shift {
            b.cx(coeff_v[i], shifted_cv[i + top_shift]);
        }
        for sh in (1..digit_hist.len()).rev() {
            b.cx(rem[rem.len() - 1], digit_hist[sh]);
            emit_fused_sign_controlled_addsub_digit_for_centered_test(
                b,
                rem,
                &shifted_v,
                digit_hist[sh],
            );
            if q_neg {
                b.x(digit_hist[sh]);
            }
            emit_fused_sign_controlled_addsub_digit_for_centered_test(
                b,
                coeff_acc,
                &shifted_cv,
                digit_hist[sh],
            );
            if q_neg {
                b.x(digit_hist[sh]);
            }
            emit_shift_right_1_nooverflow_for_centered_test(b, &shifted_v);
            emit_arithmetic_shift_right_1_exact_for_centered_test(b, &shifted_cv);
        }

        b.cx(rem[rem.len() - 1], final_neg1);
        emit_active_fused_sign_controlled_addsub_digit_for_centered_test(
            b,
            rem,
            &shifted_v,
            final_neg1,
            sign_true,
        );
        emit_active_fused_sign_controlled_addsub_digit_for_centered_test(
            b,
            coeff_acc,
            &shifted_cv,
            final_neg1,
            coeff_sign_neg,
        );
        b.ccx(final_neg1, rem[rem.len() - 1], final_neg2);
        emit_active_fused_sign_controlled_addsub_digit_for_centered_test(
            b,
            rem,
            &shifted_v,
            final_neg2,
            sign_true,
        );
        emit_active_fused_sign_controlled_addsub_digit_for_centered_test(
            b,
            coeff_acc,
            &shifted_cv,
            final_neg2,
            coeff_sign_neg,
        );

        let pos = b.alloc_qubit();
        b.cx(final_neg1, pos);
        b.x(pos);
        super::super::cmp_lt_into(b, rem, &shifted_v, final_lt_tmp);
        b.x(final_lt_tmp);
        b.ccx(pos, final_lt_tmp, final_pos_ge);
        b.x(final_lt_tmp);
        super::super::cmp_lt_into(b, rem, &shifted_v, final_lt_tmp);
        emit_active_fused_sign_controlled_addsub_digit_for_centered_test(
            b,
            rem,
            &shifted_v,
            final_pos_ge,
            sign_false,
        );
        emit_active_fused_sign_controlled_addsub_digit_for_centered_test(
            b,
            coeff_acc,
            &shifted_cv,
            final_pos_ge,
            coeff_sign_pos,
        );
        b.x(pos);
        b.cx(final_neg1, pos);
        b.free(pos);

        let half_v = b.alloc_qubits(rem.len());
        for i in 1..divisor.len() {
            b.cx(divisor[i], half_v[i - 1]);
        }
        super::super::sub_nbit_qq_fast(b, &half_v, rem);
        for i in (1..divisor.len()).rev() {
            b.cx(divisor[i], half_v[i - 1]);
        }
        b.free_vec(&half_v);

        for i in (0..coeff_v.len()).rev() {
            b.cx(coeff_v[i], shifted_cv[i]);
        }
        for i in (0..divisor.len()).rev() {
            b.cx(divisor[i], shifted_v[i]);
        }
        b.free_vec(&shifted_cv);
        b.free_vec(&shifted_v);
        b.x(sign_true);
        b.free(sign_true);
        b.free(sign_false);
    }

