    #[test]
    fn direct_centered_signnorm_det_low2_and_coeff_sign_recover_norm_sign() {
        // The coefficient-row disambiguation does not require full row
        // identity.  The determinant sign alone is still ambiguous, but it
        // combines with the live coeff_v sign bit by a simple xor.
        // For the live post-step rows, det = v*next_coeff - next_v*coeff_v is
        // exactly +/-p.  Since p is odd, det mod 4 distinguishes those two
        // cases with only the two low product bits.
        let cases = [(8usize, 251u16), (10, 1021), (12, 4093), (14, 16381)];
        for &(n, p) in &cases {
            let (
                det_collisions,
                det_states,
                det_max_mult,
                formula_collisions,
                formula_states,
                formula_max_mult,
                total_steps,
                bad_det_cases,
                low2_mismatches,
                formula_mismatches,
            ) = direct_centered_signnorm_det_low2_coeff_sign_stats(p);
            eprintln!(
                "direct-centered signnorm det-low2 coeff-sign recovery: n={n}, det_collisions={det_collisions}, det_states={det_states}, det_max_mult={det_max_mult}, formula_collisions={formula_collisions}, formula_states={formula_states}, formula_max_mult={formula_max_mult}, total_steps={total_steps}, bad_det_cases={bad_det_cases}, low2_mismatches={low2_mismatches}, formula_mismatches={formula_mismatches}"
            );
            if n == 14 {
                println!("METRIC centered_direct_signnorm_det_sign_reverse_collisions_n14={det_collisions}");
                println!("METRIC centered_direct_signnorm_det_sign_reverse_states_n14={det_states}");
                println!("METRIC centered_direct_signnorm_det_sign_reverse_max_mult_n14={det_max_mult}");
                println!("METRIC centered_direct_signnorm_det_coeffsign_reverse_collisions_n14={formula_collisions}");
                println!("METRIC centered_direct_signnorm_det_coeffsign_reverse_states_n14={formula_states}");
                println!("METRIC centered_direct_signnorm_det_coeffsign_reverse_total_steps_n14={total_steps}");
                println!("METRIC centered_direct_signnorm_det_coeffsign_reverse_max_mult_n14={formula_max_mult}");
                println!("METRIC centered_direct_signnorm_det_coeffsign_bad_det_cases_n14={bad_det_cases}");
                println!("METRIC centered_direct_signnorm_det_coeffsign_low2_mismatches_n14={low2_mismatches}");
                println!("METRIC centered_direct_signnorm_det_coeffsign_formula_mismatches_n14={formula_mismatches}");
            }
            assert_eq!(bad_det_cases, 0, "post-step determinant is not exactly +/-p");
            assert_eq!(
                low2_mismatches, 0,
                "determinant low two bits do not recover the determinant sign"
            );
            assert!(det_collisions > 0, "determinant sign alone unexpectedly recovers norm signs");
            assert_eq!(
                formula_mismatches, 0,
                "norm_sign != det_positive xor coeff_v_negative on the exact toy image"
            );
            assert_eq!(
                formula_collisions, 0,
                "determinant sign plus coeff_v sign does not recover normalization signs"
            );
            assert_eq!(formula_max_mult, 1, "det/coeff-sign image has unexpected multiplicity");
        }
    }

    #[test]
    fn direct_centered_signnorm_logical_coeff_signs_break_det_low2_cleanup() {
        // The det-low2 recovery proof above is for physically sign-normalized
        // coefficient rows.  The average-shaped logical-sign ledger keeps the
        // coefficient cneg as a separate sign bit instead.  In that frame,
        // v*next_coeff - next_v*coeff_v is often not +/-p, and the same
        // det-low2 xor coeff_v_sign predicate no longer recovers the
        // normalization sign.  Keep this pinned so the physical-row proof is
        // not accidentally promoted as a logical-sign cleanup.
        let cases = [(8usize, 251u16), (10, 1021), (12, 4093), (14, 16381)];
        for &(n, p) in &cases {
            let (
                formula_collisions,
                formula_states,
                formula_max_mult,
                total_steps,
                bad_det_cases,
                low2_mismatches,
                formula_mismatches,
            ) = direct_centered_signnorm_logical_coeff_sign_det_low2_stats(p);
            eprintln!(
                "direct-centered signnorm logical-coeff det-low2 recovery: n={n}, formula_collisions={formula_collisions}, formula_states={formula_states}, formula_max_mult={formula_max_mult}, total_steps={total_steps}, bad_det_cases={bad_det_cases}, low2_mismatches={low2_mismatches}, formula_mismatches={formula_mismatches}"
            );
            if n == 14 {
                println!("METRIC centered_direct_logsign_det_coeffsign_reverse_collisions_n14={formula_collisions}");
                println!("METRIC centered_direct_logsign_det_coeffsign_reverse_states_n14={formula_states}");
                println!("METRIC centered_direct_logsign_det_coeffsign_reverse_total_steps_n14={total_steps}");
                println!("METRIC centered_direct_logsign_det_coeffsign_reverse_max_mult_n14={formula_max_mult}");
                println!("METRIC centered_direct_logsign_det_coeffsign_bad_det_cases_n14={bad_det_cases}");
                println!("METRIC centered_direct_logsign_det_coeffsign_low2_mismatches_n14={low2_mismatches}");
                println!("METRIC centered_direct_logsign_det_coeffsign_formula_mismatches_n14={formula_mismatches}");
            }
            assert!(
                bad_det_cases > 0,
                "logical coefficient signs unexpectedly preserved the +/-p determinant"
            );
            assert_eq!(
                low2_mismatches, 0,
                "logical-sign determinant low bits changed; revisit the recovery formula"
            );
            assert!(
                formula_mismatches > 0,
                "det-low2 xor coeff_v_sign unexpectedly recovers logical-sign normalization"
            );
            assert!(
                formula_collisions > 0 && formula_max_mult == 2,
                "logical-sign formula image no longer documents the cleanup collision"
            );
        }
    }

    #[test]
    fn direct_centered_signnorm_logical_coeff_signs_low_det_residue_still_collides() {
        // The logical-sign route is only metric-shaped if reverse cleanup can
        // recover the hidden normalization sign without paying physical cnegs.
        // Give the cleanup more than the det-low2 predicate: low determinant
        // residues up to 8 bits, both live logical coefficient signs, and the
        // reverse-visible step/remainder/quotient magnitudes.  Remaining exact
        // toy collisions mean this is not a small local residue invariant.
        use std::collections::BTreeMap;

        let cases = [(8usize, 251u16), (10, 1021), (12, 4093), (14, 16381)];
        let residue_bits = [2usize, 4, 6, 8];
        let mut largest_k8_collisions = 0usize;
        let mut largest_k8_states = 0usize;
        for &(n, p) in &cases {
            for &k in &residue_bits {
                let modulus = 1i128 << k;
                let mut image: BTreeMap<(usize, i128, i128, i128, i128, bool, bool), u8> =
                    BTreeMap::new();
                let mut total_steps = 0usize;
                for x in 1..p {
                    let mut u = p as i128;
                    let mut v = x as i128;
                    let mut coeff_u = 0i128;
                    let mut coeff_v = 1i128;
                    let mut coeff_u_sign = false;
                    let mut coeff_v_sign = false;
                    let mut step = 0usize;
                    while v != 0 {
                        let adjusted = u + (v >> 1);
                        let q = adjusted / v;
                        let rem = u - q * v;
                        let sign = rem < 0;
                        let next_v = rem.abs();
                        let next_coeff = if coeff_u_sign ^ coeff_v_sign {
                            coeff_u + q * coeff_v
                        } else {
                            coeff_u - q * coeff_v
                        };
                        let next_coeff_sign = coeff_u_sign ^ sign;
                        if next_v != 0 {
                            let det = v * next_coeff - next_v * coeff_v;
                            let det_residue = det.rem_euclid(modulus);
                            *image
                                .entry((
                                    step,
                                    v,
                                    next_v,
                                    q,
                                    det_residue,
                                    coeff_v_sign,
                                    next_coeff_sign,
                                ))
                                .or_insert(0) |= 1u8 << (sign as u8);
                            total_steps += 1;
                        }
                        let old_coeff_u_sign = coeff_u_sign;
                        u = v;
                        v = next_v;
                        coeff_u = coeff_v;
                        coeff_u_sign = coeff_v_sign;
                        coeff_v = next_coeff;
                        coeff_v_sign = old_coeff_u_sign ^ sign;
                        assert_eq!(
                            coeff_v_sign, next_coeff_sign,
                            "logical coefficient-sign state update drifted"
                        );
                        step += 1;
                    }
                }
                let collisions = image.values().filter(|&&mask| mask == 0b11).count();
                let max_mult = image
                    .values()
                    .map(|mask| mask.count_ones() as usize)
                    .max()
                    .unwrap_or(0);
                eprintln!(
                    "direct-centered signnorm logical coeff signs low-det residue: n={n}, k={k}, collisions={collisions}, states={}, total_steps={total_steps}, max_mult={max_mult}",
                    image.len()
                );
                if n == 14 {
                    println!("METRIC centered_direct_logsign_det_low{k}_coeffsign_collisions_n14={collisions}");
                    println!("METRIC centered_direct_logsign_det_low{k}_coeffsign_states_n14={}", image.len());
                    println!("METRIC centered_direct_logsign_det_low{k}_coeffsign_max_mult_n14={max_mult}");
                }
                if k == 8 {
                    largest_k8_collisions = largest_k8_collisions.max(collisions);
                    largest_k8_states = largest_k8_states.max(image.len());
                }
            }
        }
        println!("METRIC centered_direct_logsign_det_low8_coeffsign_largest_collisions={largest_k8_collisions}");
        println!("METRIC centered_direct_logsign_det_low8_coeffsign_largest_states={largest_k8_states}");
        assert!(
            largest_k8_collisions > 0,
            "low 8 determinant bits plus both logical coefficient signs recover the normalization sign; price the cleanup predicate"
        );
    }

    #[test]
    fn direct_centered_signnorm_det_low2_coeff_sign_predicate_toy_is_phase_clean() {
        // Circuit reality check for the recovery predicate above.  Under the
        // row invariant, det = v*next_coeff - next_v*coeff_v is +/-p, so its
        // low two bits reveal det_positive.  This toy computes that low2 sign,
        // xors the live coeff_v sign, and frees all scratch.
        use sha3::digest::{ExtendableOutput, Update};

        const LOW_W: usize = 2;
        const COEFF_W: usize = 4;
        for p_low2 in [1u8, 3u8] {
            let mut b = super::super::B::new();
            let v = b.alloc_qubits(LOW_W);
            let next_v = b.alloc_qubits(LOW_W);
            let coeff_v = b.alloc_qubits(COEFF_W);
            let next_coeff = b.alloc_qubits(COEFF_W);
            let out = b.alloc_qubit();
            let start = b.ops.len();
            emit_toy_signnorm_det_low2_coeff_sign_predicate_for_centered_test(
                &mut b,
                [v[0], v[1]],
                [next_v[0], next_v[1]],
                [coeff_v[0], coeff_v[1]],
                [next_coeff[0], next_coeff[1]],
                coeff_v[COEFF_W - 1],
                out,
                p_low2,
            );
            let ccx = local_count_ccx_for_plusminus_cost(&b.ops[start..]);
            let peak = b.peak_qubits;
            let num_qubits = b.next_qubit as usize;
            let num_bits = b.next_bit as usize;
            let ops = b.ops;
            let mut valid_odd_det_cases = 0usize;
            for out0 in 0u64..=1 {
                for v0 in 0u64..(1u64 << LOW_W) {
                    for nv0 in 0u64..(1u64 << LOW_W) {
                        for cv0 in 0u64..(1u64 << COEFF_W) {
                            for nc0 in 0u64..(1u64 << COEFF_W) {
                                let prod1 = (v0 * (nc0 & 3)) & 3;
                                let prod2 = (nv0 * (cv0 & 3)) & 3;
                                let det_low2 = (prod1 + 4 - prod2) & 3;
                                valid_odd_det_cases += (det_low2 & 1 != 0) as usize;
                                let det_positive = if p_low2 == 3 {
                                    (det_low2 & 2) != 0
                                } else {
                                    (det_low2 & 2) == 0
                                };
                                let coeff_v_negative = (cv0 & (1u64 << (COEFF_W - 1))) != 0;
                                let expected = out0 ^ ((det_positive ^ coeff_v_negative) as u64);

                                let mut hasher = sha3::Shake128::default();
                                hasher.update(b"signnorm-det-low2-coeff-sign-predicate-v1");
                                hasher.update(&[p_low2]);
                                let mut xof = hasher.finalize_xof();
                                let mut sim =
                                    crate::sim::Simulator::new(num_qubits, num_bits, &mut xof);
                                set_slice_u512_pm(&mut sim, &v, U512::from(v0));
                                set_slice_u512_pm(&mut sim, &next_v, U512::from(nv0));
                                set_slice_u512_pm(&mut sim, &coeff_v, U512::from(cv0));
                                set_slice_u512_pm(&mut sim, &next_coeff, U512::from(nc0));
                                if out0 != 0 {
                                    *sim.qubit_mut(out) = 1;
                                }
                                sim.apply(&ops);
                                assert_eq!(sim.qubit(out) & 1, expected, "predicate mismatch p_low2={p_low2} v={v0} next_v={nv0} coeff_v={cv0} next_coeff={nc0} out0={out0}");
                                assert_eq!(
                                    get_slice_u512_pm(&sim, &v).as_limbs()[0] & 3,
                                    v0,
                                    "v changed"
                                );
                                assert_eq!(
                                    get_slice_u512_pm(&sim, &next_v).as_limbs()[0] & 3,
                                    nv0,
                                    "next_v changed"
                                );
                                assert_eq!(
                                    get_slice_u512_pm(&sim, &coeff_v).as_limbs()[0]
                                        & ((1u64 << COEFF_W) - 1),
                                    cv0,
                                    "coeff_v changed"
                                );
                                assert_eq!(
                                    get_slice_u512_pm(&sim, &next_coeff).as_limbs()[0]
                                        & ((1u64 << COEFF_W) - 1),
                                    nc0,
                                    "next_coeff changed"
                                );
                                assert_eq!(
                                    sim.global_phase() & 1,
                                    0,
                                    "unexpected phase p_low2={p_low2}"
                                );
                            }
                        }
                    }
                }
            }
            println!("METRIC centered_direct_signnorm_det_low2_coeffsign_predicate_p{p_low2}_ccx={ccx}");
            println!("METRIC centered_direct_signnorm_det_low2_coeffsign_predicate_p{p_low2}_peak_q={peak}");
            println!("METRIC centered_direct_signnorm_det_low2_coeffsign_predicate_p{p_low2}_valid_odd_det_cases={valid_odd_det_cases}");
            eprintln!(
                "Signnorm det-low2 coeff-sign predicate toy p_low2={p_low2}: ccx={ccx}, peak={peak}, valid_odd_det_cases={valid_odd_det_cases}"
            );
            assert_eq!(ccx, 14, "det-low2 predicate cost drifted");
            assert!(valid_odd_det_cases > 0, "toy did not exercise odd determinant low bits");
        }
    }

    #[test]
    fn direct_centered_signnorm_recovered_sign_naive_uncompute_is_dirty() {
        // The det-low2 predicate is phase-clean, but it is a function of the
        // post-normalized remainder.  If reverse cleanup computes that bit,
        // uses it to undo the remainder cneg, and then tries to Bennett-uncompute
        // the same predicate, one predicate input has changed.  This charges a
        // real cleanup blocker for the logical-sign route rather than treating
        // recovered signs as a free branch oracle.
        use sha3::digest::{ExtendableOutput, Update};

        const REM_W: usize = 5;
        const COEFF_W: usize = 6;
        let p = 13i128;
        let p_low2 = (p & 3) as u8;
        let mut b = super::super::B::new();
        let v = b.alloc_qubits(REM_W);
        let next_v = b.alloc_qubits(REM_W);
        let coeff_v = b.alloc_qubits(COEFF_W);
        let next_coeff = b.alloc_qubits(COEFF_W);
        let recovered = b.alloc_qubit();
        let start = b.ops.len();
        emit_toy_signnorm_det_low2_coeff_sign_predicate_for_centered_test(
            &mut b,
            [v[0], v[1]],
            [next_v[0], next_v[1]],
            [coeff_v[0], coeff_v[1]],
            [next_coeff[0], next_coeff[1]],
            coeff_v[COEFF_W - 1],
            recovered,
            p_low2,
        );
        emit_twos_cneg_exact_for_centered_test(&mut b, &next_v, recovered);
        emit_toy_signnorm_det_low2_coeff_sign_predicate_for_centered_test(
            &mut b,
            [v[0], v[1]],
            [next_v[0], next_v[1]],
            [coeff_v[0], coeff_v[1]],
            [next_coeff[0], next_coeff[1]],
            coeff_v[COEFF_W - 1],
            recovered,
            p_low2,
        );
        let ccx = local_count_ccx_for_plusminus_cost(&b.ops[start..]);
        let peak = b.peak_qubits;
        let num_qubits = b.next_qubit as usize;
        let num_bits = b.next_bit as usize;
        let ops = b.ops;
        let raw_from_i128 = |x: i128, width: usize| -> u64 {
            (x & ((1i128 << width) - 1)) as u64
        };
        let mut valid_states = 0usize;
        let mut dirty_recovered_cases = 0usize;
        let mut exercised_norm_cases = 0usize;
        let mut phase_dirty_cases = 0usize;
        for x in 1..p {
            let mut u = p;
            let mut vv = x;
            let mut coeff_u = 0i128;
            let mut coeff_vv = 1i128;
            while vv != 0 {
                let adjusted = u + (vv >> 1);
                let q = adjusted / vv;
                let rem = u - q * vv;
                let norm_sign = rem < 0;
                let next_vv = rem.abs();
                let mut next_coeff_vv = coeff_u - q * coeff_vv;
                if norm_sign {
                    next_coeff_vv = -next_coeff_vv;
                }
                if next_vv != 0 {
                    valid_states += 1;
                    exercised_norm_cases += norm_sign as usize;
                    let mut hasher = sha3::Shake128::default();
                    hasher.update(b"signnorm-recovered-sign-naive-uncompute-dirty-v1");
                    let mut xof = hasher.finalize_xof();
                    let mut sim = crate::sim::Simulator::new(num_qubits, num_bits, &mut xof);
                    set_slice_u512_pm(&mut sim, &v, U512::from(vv as u64));
                    set_slice_u512_pm(&mut sim, &next_v, U512::from(next_vv as u64));
                    set_slice_u512_pm(
                        &mut sim,
                        &coeff_v,
                        U512::from(raw_from_i128(coeff_vv, COEFF_W)),
                    );
                    set_slice_u512_pm(
                        &mut sim,
                        &next_coeff,
                        U512::from(raw_from_i128(next_coeff_vv, COEFF_W)),
                    );
                    sim.apply(&ops);
                    dirty_recovered_cases += ((sim.qubit(recovered) & 1) != 0) as usize;
                    phase_dirty_cases += ((sim.global_phase() & 1) != 0) as usize;
                }
                u = vv;
                vv = next_vv;
                coeff_u = coeff_vv;
                coeff_vv = next_coeff_vv;
            }
        }
        println!("METRIC centered_direct_signnorm_recovered_sign_naive_uncompute_ccx={ccx}");
        println!("METRIC centered_direct_signnorm_recovered_sign_naive_uncompute_peak_q={peak}");
        println!("METRIC centered_direct_signnorm_recovered_sign_naive_uncompute_valid_states={valid_states}");
        println!("METRIC centered_direct_signnorm_recovered_sign_naive_uncompute_norm_cases={exercised_norm_cases}");
        println!("METRIC centered_direct_signnorm_recovered_sign_naive_uncompute_dirty_cases={dirty_recovered_cases}");
        println!("METRIC centered_direct_signnorm_recovered_sign_naive_uncompute_phase_dirty_cases={phase_dirty_cases}");
        eprintln!(
            "Signnorm recovered-sign naive uncompute: ccx={ccx}, peak={peak}, valid={valid_states}, norm_cases={exercised_norm_cases}, dirty={dirty_recovered_cases}, phase_dirty={phase_dirty_cases}"
        );
        assert!(valid_states > 0, "toy did not produce exact post-step rows");
        assert!(exercised_norm_cases > 0, "toy did not exercise normalization");
        assert!(
            dirty_recovered_cases > 0,
            "recovered normalization sign unexpectedly Bennett-cleans after rem cneg"
        );
        assert_eq!(phase_dirty_cases, 0, "naive cleanup probe introduced phase dirt");
    }

    #[test]
    fn direct_centered_signnorm_paired_cneg_flipped_uncompute_stays_dirty() {
        // If the recovered normalization sign is used to undo both normalized
        // lanes, the determinant low bits appear to flip sign.  A tempting
        // latch cleanup is to uncompute the predicate with the opposite p mod 4
        // polarity.  The toy restores the raw rows and stays phase-clean, but
        // the latch itself remains dirty, so this is not a cleanup escape.
        use sha3::digest::{ExtendableOutput, Update};

        const REM_W: usize = 5;
        const COEFF_W: usize = 6;
        let p = 13i128;
        let p_low2 = (p & 3) as u8;
        let flipped_p_low2 = if p_low2 == 1 { 3 } else { 1 };
        let mut b = super::super::B::new();
        let v = b.alloc_qubits(REM_W);
        let next_v = b.alloc_qubits(REM_W);
        let coeff_v = b.alloc_qubits(COEFF_W);
        let next_coeff = b.alloc_qubits(COEFF_W);
        let recovered = b.alloc_qubit();
        let start = b.ops.len();
        emit_toy_signnorm_det_low2_coeff_sign_predicate_for_centered_test(
            &mut b,
            [v[0], v[1]],
            [next_v[0], next_v[1]],
            [coeff_v[0], coeff_v[1]],
            [next_coeff[0], next_coeff[1]],
            coeff_v[COEFF_W - 1],
            recovered,
            p_low2,
        );
        emit_twos_cneg_exact_for_centered_test(&mut b, &next_v, recovered);
        emit_twos_cneg_exact_for_centered_test(&mut b, &next_coeff, recovered);
        emit_toy_signnorm_det_low2_coeff_sign_predicate_for_centered_test(
            &mut b,
            [v[0], v[1]],
            [next_v[0], next_v[1]],
            [coeff_v[0], coeff_v[1]],
            [next_coeff[0], next_coeff[1]],
            coeff_v[COEFF_W - 1],
            recovered,
            flipped_p_low2,
        );
        let ccx = local_count_ccx_for_plusminus_cost(&b.ops[start..]);
        let peak = b.peak_qubits;
        let num_qubits = b.next_qubit as usize;
        let num_bits = b.next_bit as usize;
        let ops = b.ops;
        let raw_from_i128 = |x: i128, width: usize| -> u64 {
            (x & ((1i128 << width) - 1)) as u64
        };
        let mut valid_states = 0usize;
        let mut exercised_norm_cases = 0usize;
        let mut dirty_recovered_cases = 0usize;
        let mut wrong_remainder_cases = 0usize;
        let mut wrong_coeff_cases = 0usize;
        let mut phase_dirty_cases = 0usize;
        for x in 1..p {
            let mut u = p;
            let mut vv = x;
            let mut coeff_u = 0i128;
            let mut coeff_vv = 1i128;
            while vv != 0 {
                let adjusted = u + (vv >> 1);
                let q = adjusted / vv;
                let rem = u - q * vv;
                let norm_sign = rem < 0;
                let next_vv = rem.abs();
                let next_coeff_raw = coeff_u - q * coeff_vv;
                let next_coeff_norm = if norm_sign {
                    -next_coeff_raw
                } else {
                    next_coeff_raw
                };
                if next_vv != 0 {
                    valid_states += 1;
                    exercised_norm_cases += norm_sign as usize;
                    let mut hasher = sha3::Shake128::default();
                    hasher.update(b"signnorm-paired-cneg-flipped-uncompute-v1");
                    let mut xof = hasher.finalize_xof();
                    let mut sim = crate::sim::Simulator::new(num_qubits, num_bits, &mut xof);
                    set_slice_u512_pm(&mut sim, &v, U512::from(vv as u64));
                    set_slice_u512_pm(&mut sim, &next_v, U512::from(next_vv as u64));
                    set_slice_u512_pm(
                        &mut sim,
                        &coeff_v,
                        U512::from(raw_from_i128(coeff_vv, COEFF_W)),
                    );
                    set_slice_u512_pm(
                        &mut sim,
                        &next_coeff,
                        U512::from(raw_from_i128(next_coeff_norm, COEFF_W)),
                    );
                    sim.apply(&ops);
                    dirty_recovered_cases += ((sim.qubit(recovered) & 1) != 0) as usize;
                    wrong_remainder_cases += (get_slice_u512_pm(&sim, &next_v).as_limbs()[0]
                        & ((1u64 << REM_W) - 1)
                        != raw_from_i128(rem, REM_W)) as usize;
                    wrong_coeff_cases += (get_slice_u512_pm(&sim, &next_coeff).as_limbs()[0]
                        & ((1u64 << COEFF_W) - 1)
                        != raw_from_i128(next_coeff_raw, COEFF_W)) as usize;
                    phase_dirty_cases += ((sim.global_phase() & 1) != 0) as usize;
                }
                u = vv;
                vv = next_vv;
                coeff_u = coeff_vv;
                coeff_vv = next_coeff_norm;
            }
        }
        println!("METRIC centered_direct_signnorm_paired_cneg_flipped_uncompute_ccx={ccx}");
        println!("METRIC centered_direct_signnorm_paired_cneg_flipped_uncompute_peak_q={peak}");
        println!("METRIC centered_direct_signnorm_paired_cneg_flipped_uncompute_valid_states={valid_states}");
        println!("METRIC centered_direct_signnorm_paired_cneg_flipped_uncompute_norm_cases={exercised_norm_cases}");
        println!("METRIC centered_direct_signnorm_paired_cneg_flipped_uncompute_dirty_cases={dirty_recovered_cases}");
        println!("METRIC centered_direct_signnorm_paired_cneg_flipped_uncompute_wrong_remainder_cases={wrong_remainder_cases}");
        println!("METRIC centered_direct_signnorm_paired_cneg_flipped_uncompute_wrong_coeff_cases={wrong_coeff_cases}");
        println!("METRIC centered_direct_signnorm_paired_cneg_flipped_uncompute_phase_dirty_cases={phase_dirty_cases}");
        eprintln!(
            "Signnorm paired-cneg flipped uncompute: ccx={ccx}, peak={peak}, valid={valid_states}, norm_cases={exercised_norm_cases}, dirty={dirty_recovered_cases}, wrong_rem={wrong_remainder_cases}, wrong_coeff={wrong_coeff_cases}, phase_dirty={phase_dirty_cases}"
        );
        assert!(valid_states > 0, "toy did not produce exact post-step rows");
        assert!(exercised_norm_cases > 0, "toy did not exercise normalization");
        assert_eq!(
            dirty_recovered_cases, 9,
            "paired cneg flipped-predicate latch blocker changed"
        );
        assert_eq!(wrong_remainder_cases, 0, "paired cneg did not recover raw remainder");
        assert_eq!(wrong_coeff_cases, 0, "paired cneg did not recover raw coefficient");
        assert_eq!(phase_dirty_cases, 0, "paired cneg cleanup introduced phase dirt");
        assert!(
            ccx > 2 * 14,
            "paired cneg cleanup stopped charging the coefficient cneg"
        );
    }

    #[test]
